INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A1_01','talk','/tɔːk/','verb','말하다','To speak about something to one or more people.','I will {talk} about my hobby today.','오늘 제 취미에 대해 말할게요.','talk','A1','presentation',1,'person speaking audience microphone stage'),
('w_presentation_A1_02','show','/ʃoʊ/','verb','보여주다','To make something visible or display it.','Let me {show} you this picture.','이 사진을 보여드릴게요.','show','A1','presentation',1,'presentation screen projector display showing'),
('w_presentation_A1_03','tell','/tel/','verb','말하다, 알리다','To give information or explain something to someone.','I will {tell} you about my project.','제 프로젝트에 대해 말씀드릴게요.','tell','A1','presentation',1,'person explaining talking hand gesture'),
('w_presentation_A1_04','start','/stɑːrt/','verb','시작하다','To begin doing or being something.','Let us {start} the presentation now.','이제 발표를 시작하겠습니다.','start','A1','presentation',1,'presentation beginning opening podium speaker'),
('w_presentation_A1_05','end','/end/','verb','끝내다','To come to a finish or bring to a close.','We will {end} the talk in five minutes.','5분 후에 발표를 마무리하겠습니다.','end','A1','presentation',1,'presentation closing finish applause audience'),
('w_presentation_A1_06','first','/fɜːrst/','adverb','첫 번째로','Before anything or anyone else.','{First}, let me introduce myself.','먼저 자기소개를 하겠습니다.','First','A1','presentation',1,'number one first podium speaker beginning'),
('w_presentation_A1_07','next','/nekst/','adverb','다음으로','Coming immediately after the present one.','{Next}, I will show the results.','다음으로 결과를 보여드리겠습니다.','Next','A1','presentation',1,'arrow next step forward presentation slide'),
('w_presentation_A1_08','last','/læst/','adjective','마지막의','Coming after all others in time or order.','The {last} point is very important.','마지막 요점이 매우 중요합니다.','last','A1','presentation',1,'final last slide presentation conclusion'),
('w_presentation_A1_09','slide','/slaɪd/','noun','슬라이드','A single page of a presentation shown on screen.','Please look at this {slide}.','이 슬라이드를 봐주세요.','slide','A1','presentation',1,'powerpoint slide presentation screen projector'),
('w_presentation_A1_10','point','/pɔɪnt/','noun','요점','A particular fact, idea, or opinion in a discussion.','My main {point} is that practice helps.','제 주요 요점은 연습이 도움이 된다는 것입니다.','point','A1','presentation',1,'presentation key point highlight marker board'),
('w_presentation_A1_11','good','/ɡʊd/','adjective','좋은','Of high quality or a satisfactory standard.','This is a {good} example.','이것은 좋은 예입니다.','good','A1','presentation',1,'thumbs up good quality approval presentation'),
('w_presentation_A1_12','today','/təˈdeɪ/','adverb','오늘','On this present day.','{Today}, we will learn about communication.','오늘은 의사소통에 대해 배울 것입니다.','Today','A1','presentation',1,'calendar today date morning office'),
('w_presentation_A1_13','here','/hɪər/','adverb','여기','In or at this place.','{Here} is a chart to help explain.','여기 설명을 도와줄 차트가 있습니다.','Here','A1','presentation',1,'pointing chart board whiteboard here'),
('w_presentation_A1_14','look','/lʊk/','verb','보다','To direct your gaze or attention at something.','Please {look} at the screen.','화면을 봐주세요.','look','A1','presentation',1,'audience looking watching screen presentation'),
('w_presentation_A1_15','see','/siː/','verb','보다, 이해하다','To notice or become aware of something.','As you can {see}, the numbers are growing.','보시다시피 숫자가 늘고 있습니다.','see','A1','presentation',1,'graph chart data growing upward trend'),
('w_presentation_A1_16','know','/noʊ/','verb','알다','To have information or facts in your mind.','You may already {know} this fact.','이 사실을 이미 알고 계실 수도 있어요.','know','A1','presentation',1,'lightbulb knowledge understanding idea concept'),
('w_presentation_A1_17','help','/help/','verb','돕다','To make something easier or provide assistance.','This chart will {help} you understand.','이 차트가 이해하는 데 도움이 될 것입니다.','help','A1','presentation',1,'helping hand support chart data explanation'),
('w_presentation_A1_18','think','/θɪŋk/','verb','생각하다','To have an opinion or idea about something.','I {think} this is a key finding.','이것이 핵심 발견이라고 생각합니다.','think','A1','presentation',1,'thinking person idea consideration analysis'),
('w_presentation_A1_19','mean','/miːn/','verb','의미하다','To have as a meaning or to intend to say something.','What does this number {mean}?','이 숫자는 무엇을 의미하나요?','mean','A1','presentation',1,'question mark data number meaning concept'),
('w_presentation_A1_20','ready','/ˈredi/','adjective','준비된','Fully prepared for something.','I am {ready} to begin.','시작할 준비가 되었습니다.','ready','A1','presentation',1,'prepared ready speaker podium confident'),
('w_presentation_A1_21','number','/ˈnʌmbər/','noun','숫자','A value used to count or measure something.','This {number} shows our progress.','이 숫자는 우리의 진행 상황을 보여줍니다.','number','A1','presentation',1,'numbers data statistics chart bar graph'),
('w_presentation_A1_22','question','/ˈkwestʃən/','noun','질문','A sentence or phrase used to find out information.','Are there any {question}s at this point?','이 시점에 질문이 있으신가요?','question','A1','presentation',1,'audience raising hand question answer discussion'),
('w_presentation_A1_23','big','/bɪɡ/','adjective','큰','Large in size, amount, or extent.','This is a {big} change for our team.','이것은 우리 팀에 큰 변화입니다.','big','A1','presentation',1,'large important big change business growth'),
('w_presentation_A1_24','part','/pɑːrt/','noun','부분','A section or portion of something.','The second {part} will cover solutions.','두 번째 부분에서는 해결책을 다룰 것입니다.','part','A1','presentation',1,'section chapter part presentation outline'),
('w_presentation_A1_25','plan','/plæn/','noun','계획','A detailed proposal for doing or achieving something.','Our {plan} has three main steps.','우리 계획에는 세 가지 주요 단계가 있습니다.','plan','A1','presentation',1,'planning roadmap steps strategy whiteboard'),
('w_presentation_A1_26','idea','/aɪˈdiːə/','noun','아이디어','A thought or suggestion about what to do.','My main {idea} is to improve communication.','제 주요 아이디어는 의사소통을 개선하는 것입니다.','idea','A1','presentation',1,'lightbulb idea brainstorm concept creative'),
('w_presentation_A1_27','step','/step/','noun','단계','One of a series of things to do in order.','The first {step} is to identify the problem.','첫 번째 단계는 문제를 파악하는 것입니다.','step','A1','presentation',1,'steps staircase process plan roadmap'),
('w_presentation_A1_28','word','/wɜːrd/','noun','단어, 말','A unit of language or something said.','I would like to say a few {word}s.','몇 말씀 드리고 싶습니다.','word','A1','presentation',1,'words speaking text speech bubble communication'),
('w_presentation_A1_29','time','/taɪm/','noun','시간','The measured or measurable period during which an action occurs.','We have ten minutes of {time} left.','남은 시간이 10분입니다.','time','A1','presentation',1,'clock timer countdown presentation time'),
('w_presentation_A1_30','name','/neɪm/','noun','이름','The word by which someone or something is known.','My {name} is Ji-yeon and I am here to present.','제 이름은 지연이고 발표하러 왔습니다.','name','A1','presentation',1,'name tag introduction speaker badge'),
('w_presentation_A1_31','right','/raɪt/','adverb','맞아요, 좋아요','Used to confirm or agree with something.','{Right}, let us move on to the data.','좋아요, 데이터로 넘어가겠습니다.','Right','A1','presentation',1,'agreement nod confirmation presenter audience'),
('w_presentation_A1_32','give','/ɡɪv/','verb','드리다, 주다','To provide or offer something to someone.','I will {give} you a brief overview.','간략한 개요를 말씀드리겠습니다.','give','A1','presentation',1,'giving overview presenting briefing speaker'),
('w_presentation_A1_33','cover','/ˈkʌvər/','verb','다루다','To deal with a subject or include it in a talk.','Today I will {cover} three main topics.','오늘 세 가지 주요 주제를 다루겠습니다.','cover','A1','presentation',1,'outline agenda topics cover presentation plan'),
('w_presentation_A1_34','picture','/ˈpɪktʃər/','noun','그림, 사진','A visual representation or image.','This {picture} explains the concept well.','이 그림이 개념을 잘 설명해 줍니다.','picture','A1','presentation',1,'image infographic visual concept diagram'),
('w_presentation_A1_35','about','/əˈbaʊt/','preposition','~에 대하여','On the subject of something.','Today I will talk {about} teamwork.','오늘은 팀워크에 대해 이야기하겠습니다.','about','A1','presentation',1,'topic subject presentation teamwork discussion');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_A2_01','introduce','/ˌɪntrəˈdjuːs/','verb','소개하다','To present someone or something to others for the first time.','Let me {introduce} our guest speaker.','초청 강연자를 소개해 드리겠습니다.','introduce','A2','presentation',1,'introduction handshake speaker stage welcome'),
('w_presentation_A2_02','outline','/ˈaʊtlaɪn/','noun','개요, 아웃라인','A general description giving the main points of something.','Here is the {outline} of my talk.','제 발표의 개요입니다.','outline','A2','presentation',1,'outline plan agenda list presentation structure'),
('w_presentation_A2_03','summary','/ˈsʌməri/','noun','요약','A brief statement of the main points of something.','Let me give you a quick {summary}.','간단히 요약해 드리겠습니다.','summary','A2','presentation',1,'summary key points review recap presentation'),
('w_presentation_A2_04','topic','/ˈtɒpɪk/','noun','주제','A subject that is discussed, written about, or studied.','The {topic} of today''s presentation is productivity.','오늘 발표의 주제는 생산성입니다.','topic','A2','presentation',1,'topic subject theme presentation title board'),
('w_presentation_A2_05','explain','/ɪkˈspleɪn/','verb','설명하다','To make something clear by describing it in more detail.','I will {explain} how this process works.','이 과정이 어떻게 작동하는지 설명해 드리겠습니다.','explain','A2','presentation',1,'explaining whiteboard diagram process flow'),
('w_presentation_A2_06','question','/ˈkwestʃən/','noun','질문 (복수 활용)','A sentence asking for information or inviting discussion.','Please hold your {question}s until the end.','질문은 마지막까지 기다려 주세요.','question','A2','presentation',1,'Q&A session audience raising hand questions'),
('w_presentation_A2_07','answer','/ˈænsər/','verb','대답하다','To say something in response to a question.','I am happy to {answer} your questions.','질문에 기꺼이 답변해 드리겠습니다.','answer','A2','presentation',1,'answering question speaker Q&A microphone'),
('w_presentation_A2_08','audience','/ˈɔːdiəns/','noun','청중','The group of people watching or listening to a presentation.','Thank you, {audience}, for your attention.','청중 여러분, 경청해 주셔서 감사합니다.','audience','A2','presentation',1,'audience watching listening presentation hall'),
('w_presentation_A2_09','present','/prɪˈzent/','verb','발표하다','To show or demonstrate something formally to an audience.','I will {present} our quarterly results.','분기별 결과를 발표하겠습니다.','present','A2','presentation',1,'presenter stage podium quarterly results business'),
('w_presentation_A2_10','conclusion','/kənˈkluːʒən/','noun','결론','The end or final part of a speech or piece of writing.','In {conclusion}, practice makes perfect.','결론적으로, 연습이 완성을 만듭니다.','conclusion','A2','presentation',1,'conclusion ending final slide summary wrap up'),
('w_presentation_A2_11','section','/ˈsekʃən/','noun','섹션, 부분','A distinct part or subdivision of something.','The next {section} deals with marketing.','다음 섹션은 마케팅을 다룹니다.','section','A2','presentation',2,'section chapter division presentation structure'),
('w_presentation_A2_12','main','/meɪn/','adjective','주요한','Most important or largest.','The {main} goal of this project is growth.','이 프로젝트의 주요 목표는 성장입니다.','main','A2','presentation',1,'main goal objective key priority presentation'),
('w_presentation_A2_13','example','/ɪɡˈzɑːmpəl/','noun','예시','Something used to illustrate or explain a point.','Let me give you an {example}.','예를 하나 들어드리겠습니다.','example','A2','presentation',1,'example case study illustration learning'),
('w_presentation_A2_14','chart','/tʃɑːrt/','noun','차트','A sheet with information presented in the form of a diagram.','This {chart} shows our growth over time.','이 차트는 시간에 따른 성장을 보여줍니다.','chart','A2','presentation',1,'bar chart graph data visualization business'),
('w_presentation_A2_15','graph','/ɡræf/','noun','그래프','A diagram showing data and relationships between values.','As you can see on this {graph}, sales increased.','이 그래프에서 볼 수 있듯이 매출이 증가했습니다.','graph','A2','presentation',2,'line graph data trend increase decrease'),
('w_presentation_A2_16','figure','/ˈfɪɡjər/','noun','수치, 그림','A number representing an amount, or an illustration.','The {figure} on the left shows last year''s data.','왼쪽의 수치는 작년 데이터를 보여줍니다.','figure','A2','presentation',2,'data figure numbers statistics chart'),
('w_presentation_A2_17','goal','/ɡoʊl/','noun','목표','An aim or desired result.','Our {goal} is to double sales this year.','올해 목표는 매출을 두 배로 늘리는 것입니다.','goal','A2','presentation',1,'goal target achievement business objective'),
('w_presentation_A2_18','result','/rɪˈzʌlt/','noun','결과','The outcome of an action or situation.','The {result} of our survey is very clear.','설문 조사의 결과가 매우 명확합니다.','result','A2','presentation',1,'result outcome data findings survey analysis'),
('w_presentation_A2_19','reason','/ˈriːzən/','noun','이유','A cause or explanation for something.','The main {reason} for this change is efficiency.','이 변화의 주요 이유는 효율성입니다.','reason','A2','presentation',1,'reason explanation cause analysis thinking'),
('w_presentation_A2_20','problem','/ˈprɒbləm/','noun','문제','A matter or situation that is difficult or unwanted.','The {problem} we face is a lack of resources.','우리가 직면한 문제는 자원 부족입니다.','problem','A2','presentation',1,'problem challenge issue solution business'),
('w_presentation_A2_21','solution','/səˈluːʃən/','noun','해결책','A means of solving a problem or dealing with a situation.','Here is our proposed {solution}.','여기 우리가 제안하는 해결책이 있습니다.','solution','A2','presentation',1,'solution answer problem solving strategy business'),
('w_presentation_A2_22','project','/ˈprɒdʒekt/','noun','프로젝트','A plan or piece of work, usually to achieve a specific aim.','Our {project} has been running for six months.','우리 프로젝트는 6개월째 진행 중입니다.','project','A2','presentation',2,'project team collaboration planning business'),
('w_presentation_A2_23','data','/ˈdeɪtə/','noun','데이터','Facts and statistics collected together for reference.','The {data} supports our argument.','데이터가 우리의 주장을 뒷받침합니다.','data','A2','presentation',1,'data statistics numbers analysis research'),
('w_presentation_A2_24','report','/rɪˈpɔːrt/','noun','보고서','A spoken or written account of something.','According to our {report}, sales grew by 20%.','보고서에 따르면 매출이 20% 성장했습니다.','report','A2','presentation',2,'report document business analysis findings'),
('w_presentation_A2_25','change','/tʃeɪndʒ/','noun','변화','The act or process of becoming different.','This {change} will benefit the whole team.','이 변화는 팀 전체에 도움이 될 것입니다.','change','A2','presentation',2,'change transformation arrow direction business'),
('w_presentation_A2_26','increase','/ˈɪŋkriːs/','noun','증가','A rise in the amount, number, or degree of something.','There was a significant {increase} in users.','사용자 수가 크게 증가했습니다.','increase','A2','presentation',1,'increase growth arrow up chart bar graph'),
('w_presentation_A2_27','decrease','/ˈdiːkriːs/','noun','감소','A reduction in the amount, number, or degree of something.','The {decrease} in costs surprised everyone.','비용 감소가 모두를 놀라게 했습니다.','decrease','A2','presentation',2,'decrease drop arrow down chart reduction'),
('w_presentation_A2_28','total','/ˈtoʊtl/','noun','합계','The whole number or amount of something.','The {total} budget is two million dollars.','총 예산은 200만 달러입니다.','total','A2','presentation',2,'total sum budget finance numbers spreadsheet'),
('w_presentation_A2_29','compare','/kəmˈpeər/','verb','비교하다','To examine the similarities or differences between things.','Let us {compare} these two approaches.','이 두 가지 접근법을 비교해 보겠습니다.','compare','A2','presentation',2,'comparison side by side chart analysis'),
('w_presentation_A2_30','agree','/əˈɡriː/','verb','동의하다','To have the same opinion or feeling as someone.','I hope you all {agree} with this approach.','여러분 모두 이 접근법에 동의하시길 바랍니다.','agree','A2','presentation',2,'agreement consensus handshake team discussion'),
('w_presentation_A2_31','clear','/klɪər/','adjective','명확한','Easy to understand, hear, read, or see.','I hope that was {clear} for everyone.','모든 분들께 명확하게 전달되었으면 합니다.','clear','A2','presentation',1,'clarity understanding clear message communication'),
('w_presentation_A2_32','brief','/briːf/','adjective','간략한','Short in duration or using few words.','I will give a {brief} overview before we begin.','시작하기 전에 간략한 개요를 드리겠습니다.','brief','A2','presentation',2,'brief short summary overview concise'),
('w_presentation_A2_33','background','/ˈbækɡraʊnd/','noun','배경','Information about the context of something.','Let me give you some {background} information.','배경 정보를 조금 말씀드리겠습니다.','background','A2','presentation',2,'background context history information overview'),
('w_presentation_A2_34','focus','/ˈfoʊkəs/','verb','집중하다','To pay particular attention to a specific subject.','Today we will {focus} on customer retention.','오늘은 고객 유지에 집중하겠습니다.','focus','A2','presentation',1,'focus spotlight lens target goal presentation'),
('w_presentation_A2_35','share','/ʃeər/','verb','공유하다','To tell others about something or give them access to it.','I would like to {share} some key insights.','주요 인사이트를 공유하고 싶습니다.','share','A2','presentation',1,'sharing information insights knowledge team');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B1_01','highlight','/ˈhaɪlaɪt/','verb','강조하다','To draw special attention to something important.','I want to {highlight} three key points.','세 가지 핵심 포인트를 강조하고 싶습니다.','highlight','B1','presentation',1,'highlight marker key point emphasis presentation'),
('w_presentation_B1_02','transition','/trænˈzɪʃən/','noun','전환','A change or move from one state or topic to another.','Let''s make a {transition} to the next section.','다음 섹션으로 넘어가겠습니다.','transition','B1','presentation',1,'transition arrow move change flow next section'),
('w_presentation_B1_03','illustrate','/ˈɪləstreɪt/','verb','설명하다, 예시를 들다','To make something clearer by using examples or visuals.','This graph will {illustrate} my point.','이 그래프가 제 요점을 설명해 줄 것입니다.','illustrate','B1','presentation',1,'illustration diagram visual example graph'),
('w_presentation_B1_04','emphasize','/ˈemfəsaɪz/','verb','강조하다','To give special importance to something in speaking or writing.','I must {emphasize} the urgency of this issue.','이 문제의 긴급성을 강조해야 합니다.','emphasize','B1','presentation',1,'emphasis bold highlight urgent important'),
('w_presentation_B1_05','elaborate','/ɪˈlæbəreɪt/','verb','자세히 설명하다','To explain something in more detail or add more information.','Could you {elaborate} on that point?','그 요점에 대해 더 자세히 설명해 주시겠어요?','elaborate','B1','presentation',2,'detail explanation deeper dive analysis'),
('w_presentation_B1_06','overview','/ˈoʊvərˌvjuː/','noun','개요, 전체 그림','A general summary or description of a subject.','Let me begin with a quick {overview}.','간단한 개요로 시작하겠습니다.','overview','B1','presentation',1,'overview summary big picture presentation intro'),
('w_presentation_B1_07','objective','/əbˈdʒektɪv/','noun','목적, 목표','A goal or aim intended to be achieved.','Our main {objective} is to reduce costs.','우리의 주요 목적은 비용 절감입니다.','objective','B1','presentation',1,'objective goal target SMART aim business plan'),
('w_presentation_B1_08','finding','/ˈfaɪndɪŋ/','noun','발견, 조사 결과','A fact or piece of information discovered through research.','Our key {finding} is that engagement doubled.','핵심 발견은 참여도가 두 배로 증가했다는 것입니다.','finding','B1','presentation',1,'research finding discovery data insight analysis'),
('w_presentation_B1_09','result','/rɪˈzʌlt/','noun','결과 (연구·실험)','The outcome of an experiment, study, or action.','The {result}s exceeded our expectations.','결과가 우리의 기대를 뛰어넘었습니다.','result','B1','presentation',1,'results success exceeding expectations graph'),
('w_presentation_B1_10','recommend','/ˌrekəˈmend/','verb','권장하다','To suggest that someone do something or use something.','I {recommend} adopting this new strategy.','이 새로운 전략을 도입할 것을 권장합니다.','recommend','B1','presentation',1,'recommendation strategy advice suggestion business'),
('w_presentation_B1_11','approach','/əˈproʊtʃ/','noun','접근법','A way of dealing with a situation or problem.','Our {approach} differs from traditional methods.','우리의 접근법은 기존 방법과 다릅니다.','approach','B1','presentation',2,'approach method strategy alternative comparison'),
('w_presentation_B1_12','demonstrate','/ˈdemənstreɪt/','verb','시연하다, 증명하다','To show clearly by giving proof or evidence.','Let me {demonstrate} how this tool works.','이 도구가 어떻게 작동하는지 시연해 드리겠습니다.','demonstrate','B1','presentation',2,'demo demonstration live example proof evidence'),
('w_presentation_B1_13','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of parts or the way something is organized.','The {structure} of my talk has three parts.','제 발표의 구조는 세 부분으로 이루어져 있습니다.','structure','B1','presentation',1,'structure outline framework organized presentation'),
('w_presentation_B1_14','evidence','/ˈevɪdəns/','noun','증거','Facts or information available to prove something.','The {evidence} clearly supports our claim.','증거가 우리의 주장을 명확히 뒷받침합니다.','evidence','B1','presentation',1,'evidence proof data research support argument'),
('w_presentation_B1_15','implication','/ˌɪmplɪˈkeɪʃən/','noun','시사점','A conclusion that can be drawn from something.','The {implication}s of this are significant.','이것의 시사점은 매우 중요합니다.','implication','B1','presentation',2,'implication impact consequence significance meaning'),
('w_presentation_B1_16','challenge','/ˈtʃælɪndʒ/','noun','과제, 도전','A task or situation that tests someone''s abilities.','One {challenge} we faced was data collection.','우리가 직면한 과제 중 하나는 데이터 수집이었습니다.','challenge','B1','presentation',2,'challenge obstacle problem solving team'),
('w_presentation_B1_17','strategy','/ˈstrætɪdʒi/','noun','전략','A plan of action designed to achieve an overall aim.','Our {strategy} focuses on digital channels.','우리의 전략은 디지털 채널에 초점을 맞춥니다.','strategy','B1','presentation',1,'strategy plan roadmap chess business direction'),
('w_presentation_B1_18','impact','/ˈɪmpækt/','noun','영향','The strong effect or influence of one thing on another.','The {impact} of this policy was immediate.','이 정책의 영향은 즉각적이었습니다.','impact','B1','presentation',1,'impact effect influence change result business'),
('w_presentation_B1_19','trend','/trend/','noun','추세','A general direction in which something is developing.','The {trend} shows consistent improvement.','추세는 지속적인 개선을 보여줍니다.','trend','B1','presentation',1,'trend line graph upward growth market data'),
('w_presentation_B1_20','significant','/sɪɡˈnɪfɪkənt/','adjective','중요한, 상당한','Large enough to be noticed or have an effect.','This is a {significant} increase in revenue.','이것은 매출의 상당한 증가입니다.','significant','B1','presentation',1,'significant important notable achievement business'),
('w_presentation_B1_21','assumption','/əˈsʌmpʃən/','noun','가정, 전제','Something taken for granted as a starting point.','Our key {assumption} is steady market growth.','우리의 핵심 가정은 안정적인 시장 성장입니다.','assumption','B1','presentation',2,'assumption premise foundation hypothesis thinking'),
('w_presentation_B1_22','scenario','/sɪˈnɑːrioʊ/','noun','시나리오','A written outline of a possible course of events.','In the best-case {scenario}, we exceed targets.','최선의 시나리오에서는 목표를 초과합니다.','scenario','B1','presentation',2,'scenario planning options best worst case'),
('w_presentation_B1_23','proposal','/prəˈpoʊzəl/','noun','제안서','A formal plan or suggestion for others to consider.','Our {proposal} outlines three options.','제안서는 세 가지 옵션을 제시합니다.','proposal','B1','presentation',1,'proposal document business plan options review'),
('w_presentation_B1_24','benefit','/ˈbenɪfɪt/','noun','이점','An advantage or gain from something.','The {benefit}s of this approach are clear.','이 접근법의 이점은 명확합니다.','benefit','B1','presentation',1,'benefit advantage positive gain improvement'),
('w_presentation_B1_25','concern','/kənˈsɜːrn/','noun','우려, 걱정','A feeling of worry about something important.','A valid {concern} is the timeline.','타당한 우려 사항은 일정입니다.','concern','B1','presentation',2,'concern worry risk issue challenge flag'),
('w_presentation_B1_26','process','/ˈprɒses/','noun','과정, 절차','A series of steps taken to achieve a particular goal.','Let me walk you through the {process}.','과정을 순서대로 안내해 드리겠습니다.','process','B1','presentation',1,'process steps flowchart workflow procedure'),
('w_presentation_B1_27','outcome','/ˈaʊtˌkʌm/','noun','결과, 성과','The way a situation ends or the result achieved.','The desired {outcome} is a 15% cost reduction.','목표 성과는 15% 비용 절감입니다.','outcome','B1','presentation',1,'outcome result success goal achieved measurement'),
('w_presentation_B1_28','effective','/ɪˈfektɪv/','adjective','효과적인','Producing the intended result successfully.','This method proved to be highly {effective}.','이 방법은 매우 효과적인 것으로 입증되었습니다.','effective','B1','presentation',2,'effective solution result success proven method'),
('w_presentation_B1_29','relevant','/ˈreləvənt/','adjective','관련성 있는','Closely connected with or appropriate to the matter.','The most {relevant} data is shown here.','가장 관련성 있는 데이터가 여기에 표시되어 있습니다.','relevant','B1','presentation',2,'relevant related connected appropriate data'),
('w_presentation_B1_30','expand','/ɪkˈspænd/','verb','확장하다, 자세히 설명하다','To make something larger or to explain in more detail.','Let me {expand} on this point briefly.','이 부분을 잠깐 자세히 설명하겠습니다.','expand','B1','presentation',2,'expand enlarge detail deeper explanation'),
('w_presentation_B1_31','current','/ˈkɜːrənt/','adjective','현재의','Existing or happening now.','The {current} situation calls for action.','현재 상황은 행동을 요구합니다.','current','B1','presentation',2,'current now present situation analysis today'),
('w_presentation_B1_32','methodology','/ˌmeθəˈdɒlədʒi/','noun','방법론','A system of methods used in a particular area of study.','Our {methodology} is based on user interviews.','우리 방법론은 사용자 인터뷰를 기반으로 합니다.','methodology','B1','presentation',2,'methodology research method process approach'),
('w_presentation_B1_33','timeline','/ˈtaɪmˌlaɪn/','noun','일정표, 타임라인','A display of events or actions in chronological order.','Here is our project {timeline}.','여기 프로젝트 타임라인이 있습니다.','timeline','B1','presentation',1,'timeline project schedule Gantt chart milestones'),
('w_presentation_B1_34','insight','/ˈɪnsaɪt/','noun','인사이트, 통찰력','A deep and accurate understanding of something.','This data gives us a key {insight}.','이 데이터는 핵심 인사이트를 제공합니다.','insight','B1','presentation',1,'insight discovery understanding data analysis'),
('w_presentation_B1_35','initiative','/ɪˈnɪʃɪətɪv/','noun','이니셔티브, 계획','A new plan or action intended to solve a problem.','This {initiative} will launch in Q3.','이 이니셔티브는 3분기에 시작됩니다.','initiative','B1','presentation',2,'initiative launch project plan start program');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_B2_01','quantify','/ˈkwɒntɪfaɪ/','verb','수치화하다','To express or measure something as a quantity.','We need to {quantify} the potential gains.','잠재적 이익을 수치화할 필요가 있습니다.','quantify','B2','presentation',1,'quantify numbers metrics measurement data chart'),
('w_presentation_B2_02','juxtapose','/ˌdʒʌkstəˈpoʊz/','verb','병치하다, 나란히 놓다','To place two things close together for comparison or contrast.','Let me {juxtapose} the two models.','두 모델을 나란히 비교해 보겠습니다.','juxtapose','B2','presentation',2,'comparison side by side contrast two options'),
('w_presentation_B2_03','contextualize','/kənˈtekstʃuəlaɪz/','verb','맥락화하다','To place something in its context to make it understandable.','It is important to {contextualize} these results.','이 결과를 맥락화하는 것이 중요합니다.','contextualize','B2','presentation',2,'context background framework understanding analysis'),
('w_presentation_B2_04','articulate','/ɑːrˈtɪkjuleɪt/','verb','명확히 표현하다','To express thoughts or feelings clearly and effectively in words.','She can {articulate} complex ideas simply.','그녀는 복잡한 아이디어를 간단하게 표현할 수 있습니다.','articulate','B2','presentation',1,'clear communication speech articulate express'),
('w_presentation_B2_05','facilitate','/fəˈsɪlɪteɪt/','verb','촉진하다, 진행을 돕다','To make an action or process easier or smoother.','This tool will {facilitate} collaboration.','이 도구는 협업을 촉진할 것입니다.','facilitate','B2','presentation',2,'facilitate enable support help process smooth'),
('w_presentation_B2_06','compelling','/kəmˈpelɪŋ/','adjective','설득력 있는','Evoking interest, attention, or admiration in a powerful way.','The data presents a {compelling} argument.','데이터가 설득력 있는 주장을 제시합니다.','compelling','B2','presentation',1,'compelling argument persuasive strong powerful case'),
('w_presentation_B2_07','persuasive','/pərˈsweɪsɪv/','adjective','설득력 있는','Good at convincing people to believe or do something.','Her {persuasive} delivery won over the board.','그녀의 설득력 있는 발표가 이사회를 설득했습니다.','persuasive','B2','presentation',1,'persuasive speech convince audience board winning'),
('w_presentation_B2_08','coherent','/koʊˈhɪərənt/','adjective','일관된, 조리 있는','Logical and well-organized, forming a unified whole.','Our argument is {coherent} and well-supported.','우리의 주장은 일관되고 잘 뒷받침됩니다.','coherent','B2','presentation',1,'coherent logical organized structured argument'),
('w_presentation_B2_09','credibility','/ˌkredɪˈbɪlɪti/','noun','신뢰성','The quality of being trusted and believed in.','Citing sources builds your {credibility}.','출처를 인용하면 신뢰성이 높아집니다.','credibility','B2','presentation',1,'credibility trust source citation research reliable'),
('w_presentation_B2_10','narrative','/ˈnærətɪv/','noun','내러티브, 서사','A spoken or written account that connects ideas into a story.','The {narrative} of this data is one of growth.','이 데이터의 내러티브는 성장에 관한 것입니다.','narrative','B2','presentation',1,'narrative story arc data storytelling presentation'),
('w_presentation_B2_11','refute','/rɪˈfjuːt/','verb','반박하다','To prove that something is wrong or incorrect.','Our data {refute}s the competitor''s claims.','우리 데이터가 경쟁사의 주장을 반박합니다.','refute','B2','presentation',2,'refute counter argument rebuttal evidence proof'),
('w_presentation_B2_12','substantiate','/səbˈstænʃieɪt/','verb','뒷받침하다, 증명하다','To provide evidence to support or prove a claim.','We can {substantiate} every figure presented.','제시된 모든 수치를 뒷받침할 수 있습니다.','substantiate','B2','presentation',2,'evidence proof support data back up claim'),
('w_presentation_B2_13','nuance','/ˈnjuːɑːns/','noun','뉘앙스','A subtle difference in meaning, expression, or sound.','There is an important {nuance} here worth noting.','여기서 주목할 만한 중요한 뉘앙스가 있습니다.','nuance','B2','presentation',2,'nuance subtle difference detail precision meaning'),
('w_presentation_B2_14','benchmark','/ˈbentʃˌmɑːrk/','noun','기준점, 벤치마크','A standard against which things may be compared.','Our results exceeded the industry {benchmark}.','우리 결과가 업계 기준을 초과했습니다.','benchmark','B2','presentation',1,'benchmark standard comparison industry performance'),
('w_presentation_B2_15','leverage','/ˈlevərɪdʒ/','verb','활용하다','To use something to maximum advantage.','We can {leverage} our brand recognition.','우리 브랜드 인지도를 활용할 수 있습니다.','leverage','B2','presentation',2,'leverage advantage utilize maximize asset strategy'),
('w_presentation_B2_16','mitigate','/ˈmɪtɪɡeɪt/','verb','완화하다','To make something less severe or serious.','Steps were taken to {mitigate} the risks.','리스크를 완화하기 위한 조치가 취해졌습니다.','mitigate','B2','presentation',2,'mitigate reduce risk management solution strategy'),
('w_presentation_B2_17','stakeholder','/ˈsteɪkˌhoʊldər/','noun','이해관계자','A person with an interest or concern in a business or project.','All {stakeholder}s have been consulted.','모든 이해관계자와 협의했습니다.','stakeholder','B2','presentation',1,'stakeholder team executive management consulting'),
('w_presentation_B2_18','scalable','/ˈskeɪləbəl/','adjective','확장 가능한','Able to be changed in size or scale to meet changing needs.','The solution we propose is {scalable}.','우리가 제안하는 솔루션은 확장 가능합니다.','scalable','B2','presentation',2,'scalable growth expand flexible technology solution'),
('w_presentation_B2_19','prioritize','/praɪˈɔːrɪtaɪz/','verb','우선순위를 정하다','To treat something as more important than other things.','We need to {prioritize} the highest-impact items.','영향력이 가장 큰 항목을 우선시해야 합니다.','prioritize','B2','presentation',1,'prioritize ranking order importance matrix'),
('w_presentation_B2_20','optimize','/ˈɒptɪmaɪz/','verb','최적화하다','To make the best or most effective use of something.','We plan to {optimize} the workflow.','워크플로우를 최적화할 계획입니다.','optimize','B2','presentation',1,'optimize improve efficiency best performance'),
('w_presentation_B2_21','trajectory','/trəˈdʒektəri/','noun','궤적, 방향','The path followed by a moving object or a course of action.','The {trajectory} of growth has been steep.','성장 궤적이 가파르게 이어져 왔습니다.','trajectory','B2','presentation',2,'trajectory path direction growth curve upward'),
('w_presentation_B2_22','catalyst','/ˈkætəlɪst/','noun','촉매제','A person or thing that causes a change or reaction.','This event was the {catalyst} for our pivot.','이 사건이 우리 방향 전환의 촉매제였습니다.','catalyst','B2','presentation',2,'catalyst change trigger event spark transformation'),
('w_presentation_B2_23','viable','/ˈvaɪəbəl/','adjective','실행 가능한','Capable of working successfully or feasible.','Option B is the most {viable} solution.','옵션 B가 가장 실행 가능한 솔루션입니다.','viable','B2','presentation',1,'viable feasible option solution practical choice'),
('w_presentation_B2_24','granular','/ˈɡrænjʊlər/','adjective','세부적인, 세밀한','Having a fine or detailed level of analysis or description.','The {granular} data reveals a hidden trend.','세밀한 데이터가 숨겨진 추세를 드러냅니다.','granular','B2','presentation',2,'granular detail level data micro analysis deep'),
('w_presentation_B2_25','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다','To combine different elements into a coherent whole.','We {synthesize} data from multiple sources.','여러 출처의 데이터를 종합합니다.','synthesize','B2','presentation',1,'synthesize combine integrate data sources analysis'),
('w_presentation_B2_26','transparency','/trænsˈpærənsi/','noun','투명성','Being open and not hiding information.','We value {transparency} in our reporting.','보고에서 투명성을 중요하게 생각합니다.','transparency','B2','presentation',2,'transparency open honest reporting clear communication'),
('w_presentation_B2_27','validate','/ˈvælɪdeɪt/','verb','검증하다','To confirm that something is correct or justified.','We {validate}d our model with real data.','실제 데이터로 모델을 검증했습니다.','validate','B2','presentation',2,'validate verify confirm test data proof'),
('w_presentation_B2_28','robust','/roʊˈbʌst/','adjective','견고한, 탄탄한','Strong and healthy or vigorous; able to withstand challenges.','We have built a {robust} methodology.','견고한 방법론을 구축했습니다.','robust','B2','presentation',2,'robust strong solid reliable methodology research'),
('w_presentation_B2_29','holistic','/hoʊˈlɪstɪk/','adjective','전체론적인','Considering all parts of something together rather than separately.','We take a {holistic} view of the problem.','문제를 전체론적 관점에서 바라봅니다.','holistic','B2','presentation',2,'holistic whole system perspective integrated view'),
('w_presentation_B2_30','momentum','/moʊˈmentəm/','noun','기세, 모멘텀','The force that keeps an activity developing after it starts.','We need to maintain {momentum} through Q4.','4분기 내내 기세를 유지해야 합니다.','momentum','B2','presentation',2,'momentum growth speed forward motion continue'),
('w_presentation_B2_31','discrepancy','/dɪˈskrepənsi/','noun','불일치, 차이','A difference between two or more things that should be the same.','There is a {discrepancy} in the figures.','수치에 불일치가 있습니다.','discrepancy','B2','presentation',2,'discrepancy difference gap mismatch data error'),
('w_presentation_B2_32','actionable','/ˈækʃənəbəl/','adjective','바로 실행 가능한','Able to be acted on; providing clear steps to take.','These insights are {actionable} immediately.','이 인사이트들은 즉시 실행 가능합니다.','actionable','B2','presentation',1,'actionable steps concrete plan action immediate'),
('w_presentation_B2_33','iteration','/ˌɪtəˈreɪʃən/','noun','반복, 이터레이션','A new version of a process or design, based on review.','The third {iteration} showed the best results.','세 번째 이터레이션에서 최고의 결과가 나왔습니다.','iteration','B2','presentation',2,'iteration cycle improve version agile development'),
('w_presentation_B2_34','alignment','/əˈlaɪnmənt/','noun','정렬, 일치','Agreement or cooperation among people or groups.','We need strategic {alignment} before moving forward.','앞으로 나아가기 전에 전략적 정렬이 필요합니다.','alignment','B2','presentation',1,'alignment agreement team strategy unified direction'),
('w_presentation_B2_35','projection','/prəˈdʒekʃən/','noun','전망, 예측치','An estimate of future outcomes based on current data.','Our five-year {projection} looks very promising.','5년 전망이 매우 유망하게 보입니다.','projection','B2','presentation',1,'projection forecast future estimate graph financial');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C1_01','rhetoric','/ˈretərɪk/','noun','수사학, 수사법','The art of effective or persuasive speaking or writing.','Mastering {rhetoric} will transform your presentations.','수사법을 익히면 발표가 달라집니다.','rhetoric','C1','presentation',1,'rhetoric persuasion speech oratory debate stage'),
('w_presentation_C1_02','discourse','/ˈdɪskɔːrs/','noun','담화, 담론','Written or spoken communication or debate.','Academic {discourse} requires precise language.','학문적 담론은 정확한 언어를 요구합니다.','discourse','C1','presentation',2,'discourse discussion academic language debate forum'),
('w_presentation_C1_03','deconstruct','/ˌdiːkənˈstrʌkt/','verb','해체 분석하다','To analyze something by breaking it down into its parts.','Let me {deconstruct} the argument step by step.','주장을 단계별로 분해해 분석해 보겠습니다.','deconstruct','C1','presentation',2,'deconstruct analyze break down components parts'),
('w_presentation_C1_04','paradigm','/ˈpærədaɪm/','noun','패러다임','A typical example or model, or a framework of assumptions.','This technology represents a new {paradigm}.','이 기술은 새로운 패러다임을 나타냅니다.','paradigm','C1','presentation',1,'paradigm shift model framework new era change'),
('w_presentation_C1_05','framework','/ˈfreɪmwɜːrk/','noun','프레임워크, 틀','A basic structure underlying a system or concept.','Our analysis uses a four-part {framework}.','우리 분석은 네 부분으로 이루어진 프레임워크를 사용합니다.','framework','C1','presentation',1,'framework structure model analysis four quadrant'),
('w_presentation_C1_06','proposition','/ˌprɒpəˈzɪʃən/','noun','명제, 핵심 주장','A statement or assertion that expresses a judgment or opinion.','Our core value {proposition} is clear.','우리의 핵심 가치 명제는 명확합니다.','proposition','C1','presentation',1,'proposition value statement argument claim thesis'),
('w_presentation_C1_07','empirical','/ɪmˈpɪrɪkəl/','adjective','경험적인, 실증적인','Based on observation or experience rather than theory.','Our conclusions are grounded in {empirical} data.','우리의 결론은 실증적 데이터에 근거합니다.','empirical','C1','presentation',1,'empirical data research evidence observation fact'),
('w_presentation_C1_08','analytical','/ˌænəˈlɪtɪkəl/','adjective','분석적인','Using analysis or logic to examine something carefully.','An {analytical} approach reveals underlying patterns.','분석적 접근법이 내재된 패턴을 드러냅니다.','analytical','C1','presentation',1,'analytical thinking data logic systematic approach'),
('w_presentation_C1_09','synthesize','/ˈsɪnθəsaɪz/','verb','종합하다 (학제적)','To produce something by combining elements from multiple sources.','We {synthesize} research from multiple disciplines.','여러 학문 분야의 연구를 종합합니다.','synthesize','C1','presentation',1,'synthesize research combine disciplines integrate whole'),
('w_presentation_C1_10','infer','/ɪnˈfɜːr/','verb','추론하다','To reach a conclusion based on evidence and reasoning.','We can {infer} causation from these results.','이 결과에서 인과관계를 추론할 수 있습니다.','infer','C1','presentation',2,'infer conclude reason evidence logic analysis'),
('w_presentation_C1_11','correlate','/ˈkɒrəleɪt/','verb','상관관계가 있다','To have a mutual relationship or connection.','User engagement strongly {correlate}s with retention.','사용자 참여는 유지율과 강하게 상관관계가 있습니다.','correlate','C1','presentation',2,'correlation relationship data variables statistical'),
('w_presentation_C1_12','critique','/krɪˈtiːk/','verb','비평하다','To analyze and judge a work or idea in a detailed way.','I will {critique} the existing approach first.','먼저 기존 접근법을 비평하겠습니다.','critique','C1','presentation',2,'critique review analysis evaluation judgment academic'),
('w_presentation_C1_13','conceptualize','/kənˈseptʃuəlaɪz/','verb','개념화하다','To form a concept or idea of something in the mind.','We {conceptualize}d the solution as a feedback loop.','솔루션을 피드백 루프로 개념화했습니다.','conceptualize','C1','presentation',2,'conceptualize idea model thinking abstraction design'),
('w_presentation_C1_14','divergent','/daɪˈvɜːrdʒənt/','adjective','발산적인, 다른','Tending to be different or developing in different directions.','The two models produced {divergent} outcomes.','두 모델이 다른 결과를 만들어냈습니다.','divergent','C1','presentation',2,'divergent different opposite split path comparison'),
('w_presentation_C1_15','convergent','/kənˈvɜːrdʒənt/','adjective','수렴적인','Tending to come together toward a common point.','All data sets show {convergent} trends.','모든 데이터 세트가 수렴하는 추세를 보입니다.','convergent','C1','presentation',2,'convergent same direction unified trend agreement'),
('w_presentation_C1_16','nuanced','/ˈnjuːɑːnst/','adjective','세밀한, 뉘앙스 있는','Having subtle distinctions or fine differences.','Her {nuanced} analysis impressed the committee.','그녀의 세밀한 분석이 위원회에 깊은 인상을 주었습니다.','nuanced','C1','presentation',1,'nuanced subtle detail precision careful analysis'),
('w_presentation_C1_17','normative','/ˈnɔːrmətɪv/','adjective','규범적인','Relating to a standard or norm, especially of behavior.','We move from descriptive to {normative} analysis.','기술적 분석에서 규범적 분석으로 이동합니다.','normative','C1','presentation',2,'normative standard prescriptive recommendation policy'),
('w_presentation_C1_18','extrapolate','/ɪkˈstræpəleɪt/','verb','외삽하여 추정하다','To extend a conclusion from known data to an unknown area.','We can {extrapolate} from current trends.','현재 추세에서 미래를 추정 연장할 수 있습니다.','extrapolate','C1','presentation',2,'extrapolate predict forecast trend extension future'),
('w_presentation_C1_19','hypothesis','/haɪˈpɒθɪsɪs/','noun','가설','A proposed explanation made on limited evidence.','Our {hypothesis} was supported by the trial data.','가설은 실험 데이터로 뒷받침되었습니다.','hypothesis','C1','presentation',1,'hypothesis test research science experiment prove'),
('w_presentation_C1_20','contingency','/kənˈtɪndʒənsi/','noun','비상 계획, 만일의 경우','A future event or circumstance that is possible but uncertain.','We have a {contingency} plan for each risk.','각 리스크에 대한 비상 계획이 있습니다.','contingency','C1','presentation',2,'contingency backup plan risk management safety'),
('w_presentation_C1_21','delineate','/dɪˈlɪnieɪt/','verb','명확히 구분하다','To describe or indicate something precisely.','I will {delineate} the scope of this study.','이 연구의 범위를 명확히 구분해 드리겠습니다.','delineate','C1','presentation',2,'delineate define scope boundary clarify outline'),
('w_presentation_C1_22','causality','/kɔːˈzæləti/','noun','인과관계','The relationship between cause and effect.','We must not confuse correlation with {causality}.','상관관계를 인과관계로 혼동해서는 안 됩니다.','causality','C1','presentation',2,'causality cause effect relationship data statistics'),
('w_presentation_C1_23','disseminate','/dɪˈsemɪneɪt/','verb','전파하다, 보급하다','To spread information widely.','We plan to {disseminate} these findings broadly.','이 결과를 널리 전파할 계획입니다.','disseminate','C1','presentation',2,'disseminate spread share publish broadcast research'),
('w_presentation_C1_24','dichotomy','/daɪˈkɒtəmi/','noun','이분법','A division or contrast between two things as opposites.','There is a false {dichotomy} between speed and quality.','속도와 품질 사이에는 잘못된 이분법이 있습니다.','dichotomy','C1','presentation',2,'dichotomy binary two sides contrast opposition'),
('w_presentation_C1_25','interrogate','/ɪnˈterəɡeɪt/','verb','면밀히 검토하다','To examine something critically and in detail.','We need to {interrogate} the underlying assumptions.','기저 가정을 면밀히 검토해야 합니다.','interrogate','C1','presentation',2,'interrogate examine question critically scrutiny'),
('w_presentation_C1_26','generalize','/ˈdʒenərəlaɪz/','verb','일반화하다','To make a general statement from specific instances.','We should be careful not to over-{generalize}.','과도하게 일반화하지 않도록 주의해야 합니다.','generalize','C1','presentation',2,'generalize broad conclusion caution limitation'),
('w_presentation_C1_27','precedent','/ˈpresɪdənt/','noun','선례','An earlier event that is taken as a guide for the future.','This sets a {precedent} for future decisions.','이것이 미래 결정의 선례를 세웁니다.','precedent','C1','presentation',2,'precedent history example past reference guide'),
('w_presentation_C1_28','quantitative','/ˈkwɒntɪtətɪv/','adjective','정량적인','Relating to the measurement of quantity or amount.','The {quantitative} findings are compelling.','정량적 발견이 설득력 있습니다.','quantitative','C1','presentation',1,'quantitative data numbers statistics measurement research'),
('w_presentation_C1_29','qualitative','/ˈkwɒlɪtətɪv/','adjective','정성적인','Relating to the quality or character of something.','The {qualitative} feedback revealed key themes.','정성적 피드백에서 핵심 주제가 드러났습니다.','qualitative','C1','presentation',1,'qualitative interview theme insight user research'),
('w_presentation_C1_30','iterative','/ˈɪtərətɪv/','adjective','반복적인, 점진적인','Characterized by repetition of a process to achieve a result.','Our design follows an {iterative} process.','우리 디자인은 반복적인 과정을 따릅니다.','iterative','C1','presentation',2,'iterative process cycle improve agile development'),
('w_presentation_C1_31','posit','/ˈpɒzɪt/','verb','가정하다, 주장하다','To put forward as a fact or basis for argument.','I would {posit} that user trust is the key variable.','사용자 신뢰가 핵심 변수라고 주장하고자 합니다.','posit','C1','presentation',2,'posit argue assert claim academic presentation'),
('w_presentation_C1_32','substantive','/ˈsʌbstəntɪv/','adjective','실질적인, 핵심적인','Having a firm basis in reality and being important or meaningful.','We need {substantive} change, not cosmetic fixes.','표면적 수정이 아닌 실질적인 변화가 필요합니다.','substantive','C1','presentation',2,'substantive real meaningful significant change impact'),
('w_presentation_C1_33','granularity','/ˌɡrænjʊˈlærɪti/','noun','세분화, 세부 수준','The level of detail or precision in data or analysis.','The {granularity} of this dataset is exceptional.','이 데이터셋의 세분화 수준은 탁월합니다.','granularity','C1','presentation',2,'granularity detail precision data level analysis'),
('w_presentation_C1_34','axiom','/ˈæksiəm/','noun','공리, 자명한 이치','A statement accepted as true as the basis for argument.','The first {axiom} of our model is user rationality.','우리 모델의 첫 번째 공리는 사용자 합리성입니다.','axiom','C1','presentation',2,'axiom truth principle foundation logic mathematics'),
('w_presentation_C1_35','reframe','/ˌriːˈfreɪm/','verb','재구성하다','To frame something in a different way to change how it is perceived.','Let us {reframe} this challenge as an opportunity.','이 도전을 기회로 재구성해 봅시다.','reframe','C1','presentation',1,'reframe perspective shift mindset opportunity challenge');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_presentation_C2_01','epistemological','/ɪˌpɪstɪməˈlɒdʒɪkəl/','adjective','인식론적인','Relating to the theory of knowledge, especially how it is acquired.','This raises {epistemological} questions about data validity.','이것은 데이터 타당성에 대한 인식론적 질문을 제기합니다.','epistemological','C2','presentation',2,'epistemology knowledge theory philosophy research validity'),
('w_presentation_C2_02','heuristic','/hjʊˈrɪstɪk/','adjective','발견적인, 경험 탐색적인','Enabling discovery through practical experience rather than a set formula.','We applied a {heuristic} approach to the analysis.','분석에 발견적 접근법을 적용했습니다.','heuristic','C2','presentation',2,'heuristic discovery method practical rule of thumb'),
('w_presentation_C2_03','ontological','/ˌɒntəˈlɒdʒɪkəl/','adjective','존재론적인','Relating to the branch of metaphysics dealing with the nature of being.','The {ontological} assumptions underpin the framework.','존재론적 가정이 프레임워크의 기반을 이룹니다.','ontological','C2','presentation',2,'ontology being existence nature philosophy framework'),
('w_presentation_C2_04','phenomenological','/fɪˌnɒmɪnəˈlɒdʒɪkəl/','adjective','현상학적인','Relating to the study of structures of experience and consciousness.','A {phenomenological} lens reveals lived experience.','현상학적 렌즈가 살아있는 경험을 드러냅니다.','phenomenological','C2','presentation',2,'phenomenological experience consciousness qualitative research'),
('w_presentation_C2_05','dialectical','/ˌdaɪəˈlektɪkəl/','adjective','변증법적인','Relating to the logical discussion of ideas through opposing arguments.','The {dialectical} tension drives innovation.','변증법적 긴장이 혁신을 이끕니다.','dialectical','C2','presentation',2,'dialectical debate tension opposing synthesis Hegel'),
('w_presentation_C2_06','praxis','/ˈpræksɪs/','noun','실천, 프락시스','The process of putting theory into practice; practice informed by theory.','Theory without {praxis} remains abstract.','실천이 없는 이론은 추상에 머뭅니다.','praxis','C2','presentation',2,'praxis practice theory action application real world'),
('w_presentation_C2_07','hermeneutic','/ˌhɜːrmɪˈnjuːtɪk/','adjective','해석학적인','Relating to interpretation, especially of texts or data.','A {hermeneutic} reading of the data is necessary.','데이터에 대한 해석학적 독해가 필요합니다.','hermeneutic','C2','presentation',2,'hermeneutic interpretation meaning text reading analysis'),
('w_presentation_C2_08','meta-analysis','/ˈmetə əˈnæləsɪs/','noun','메타분석','A statistical analysis combining results of multiple scientific studies.','Our {meta-analysis} covered forty primary studies.','메타분석은 40개의 기본 연구를 다루었습니다.','meta-analysis','C2','presentation',1,'meta-analysis systematic review studies aggregate data'),
('w_presentation_C2_09','positivist','/ˈpɒzɪtɪvɪst/','adjective','실증주의적인','Based on the philosophy that knowledge derives only from measurable phenomena.','A strictly {positivist} stance ignores context.','엄격한 실증주의적 입장은 맥락을 무시합니다.','positivist','C2','presentation',2,'positivism empirical measurable science objective'),
('w_presentation_C2_10','constructivist','/kənˈstrʌktɪvɪst/','adjective','구성주의적인','Relating to the view that knowledge is actively constructed by learners.','A {constructivist} paradigm values co-creation.','구성주의 패러다임은 공동 창조를 중시합니다.','constructivist','C2','presentation',2,'constructivism knowledge learning context subjective'),
('w_presentation_C2_11','axiom','/ˈæksiəm/','noun','공리 (수사학적 맥락)','A self-evident truth used as a foundational premise in an argument.','Begin with an {axiom} your audience already accepts.','청중이 이미 받아들이는 공리로 시작하세요.','axiom','C2','presentation',2,'axiom premise truth foundation argument rhetoric'),
('w_presentation_C2_12','reification','/ˌriːɪfɪˈkeɪʃən/','noun','구체화, 실물화','The treatment of an abstract concept as a concrete or material thing.','The {reification} of data can mislead audiences.','데이터의 실물화는 청중을 오도할 수 있습니다.','reification','C2','presentation',2,'reification abstract concrete material concept data'),
('w_presentation_C2_13','verisimilitude','/ˌverɪsɪˈmɪlɪtjuːd/','noun','사실성, 그럴듯함','The appearance of being true or real.','High {verisimilitude} increases audience trust.','높은 사실성은 청중의 신뢰를 높입니다.','verisimilitude','C2','presentation',2,'verisimilitude realism authenticity believable narrative'),
('w_presentation_C2_14','exegesis','/ˌeksɪˈdʒiːsɪs/','noun','주석, 상세 해석','A critical explanation or interpretation of a text or dataset.','The {exegesis} of the survey results took weeks.','설문 결과의 주석 작업에 몇 주가 걸렸습니다.','exegesis','C2','presentation',2,'exegesis interpretation commentary analysis text deep'),
('w_presentation_C2_15','syllogism','/ˈsɪlədʒɪzəm/','noun','삼단논법','A kind of logical argument using deductive reasoning from premises.','The argument follows a classic {syllogism}.','논거는 고전적 삼단논법을 따릅니다.','syllogism','C2','presentation',2,'syllogism logic deduction premise conclusion argument'),
('w_presentation_C2_16','tautology','/tɔːˈtɒlədʒi/','noun','동어반복','Saying the same thing twice in different words; needless repetition.','Avoid {tautology} to keep your argument sharp.','동어반복을 피해 논거를 날카롭게 유지하세요.','tautology','C2','presentation',2,'tautology repetition redundant argument writing logic'),
('w_presentation_C2_17','apotheosis','/əˌpɒθiˈoʊsɪs/','noun','절정, 최고점','The highest point of development; a perfect example of something.','This presentation is the {apotheosis} of our research.','이 발표는 우리 연구의 절정입니다.','apotheosis','C2','presentation',2,'apotheosis peak pinnacle achievement excellence best'),
('w_presentation_C2_18','polemic','/pəˈlemɪk/','noun','논쟁, 논박','A strong verbal or written attack on someone''s opinions or argument.','The paper is a well-researched {polemic}.','논문은 잘 연구된 논박입니다.','polemic','C2','presentation',2,'polemic argument attack critique debate controversy'),
('w_presentation_C2_19','triangulation','/traɪˌæŋɡjʊˈleɪʃən/','noun','삼각검증','The use of multiple methods or data sources to validate findings.','{Triangulation} of sources strengthens the argument.','출처의 삼각검증이 논거를 강화합니다.','triangulation','C2','presentation',1,'triangulation multiple sources validation research robust'),
('w_presentation_C2_20','abductive','/æbˈdʌktɪv/','adjective','귀추적인','Relating to inference to the best explanation from available evidence.','We used {abductive} reasoning to reach our conclusion.','귀추적 추론을 사용해 결론에 도달했습니다.','abductive','C2','presentation',2,'abductive reasoning inference best explanation logic'),
('w_presentation_C2_21','intersubjectivity','/ˌɪntərsəbˌdʒektɪˈvɪtɪ/','noun','상호주관성','Shared understanding between two or more individuals.','{Intersubjectivity} is key to qualitative research validity.','상호주관성은 정성 연구 타당성의 핵심입니다.','intersubjectivity','C2','presentation',2,'intersubjectivity shared understanding qualitative research'),
('w_presentation_C2_22','heterodox','/ˈhetərədɒks/','adjective','비정통적인, 이단적인','Not conforming to established or accepted beliefs or standards.','This {heterodox} approach challenges the consensus.','이 비정통적 접근법은 합의에 도전합니다.','heterodox','C2','presentation',2,'heterodox unconventional challenge consensus alternative'),
('w_presentation_C2_23','semiotics','/ˌsiːmiˈɒtɪks/','noun','기호학','The study of signs and symbols and their use or interpretation.','{Semiotics} informs how we design our slides.','기호학은 슬라이드 디자인 방식에 영향을 줍니다.','semiotics','C2','presentation',2,'semiotics signs symbols meaning design visual language'),
('w_presentation_C2_24','reflexivity','/ˌriːflekˈsɪvɪti/','noun','성찰성','The practice of critically examining one''s own assumptions and methods.','{Reflexivity} strengthens the credibility of research.','성찰성이 연구의 신뢰성을 강화합니다.','reflexivity','C2','presentation',2,'reflexivity self-awareness researcher bias critical'),
('w_presentation_C2_25','teleological','/ˌteliəˈlɒdʒɪkəl/','adjective','목적론적인','Relating to explanation of phenomena in terms of goals or purposes.','The argument is {teleological} in nature.','논거는 본질적으로 목적론적입니다.','teleological','C2','presentation',2,'teleological purpose goal driven argument reason'),
('w_presentation_C2_26','reductionism','/rɪˈdʌkʃənɪzəm/','noun','환원주의','The practice of analyzing complex things by reducing them to simpler parts.','Pure {reductionism} misses emergent phenomena.','순수 환원주의는 창발적 현상을 놓칩니다.','reductionism','C2','presentation',2,'reductionism simplify parts whole emergent complex'),
('w_presentation_C2_27','falsifiability','/ˌfɔːlsɪfaɪəˈbɪlɪti/','noun','반증가능성','The capacity for a statement to be contradicted by evidence.','A good hypothesis must have {falsifiability}.','좋은 가설은 반증가능성을 갖추어야 합니다.','falsifiability','C2','presentation',2,'falsifiability Popper science hypothesis testable'),
('w_presentation_C2_28','bricolage','/ˌbrɪkəˈlɑːʒ/','noun','브리콜라주','A construction or approach made from a diverse range of available elements.','The methodology is a {bricolage} of approaches.','방법론은 다양한 접근법의 브리콜라주입니다.','bricolage','C2','presentation',2,'bricolage mixed methods creative eclectic approach'),
('w_presentation_C2_29','instantiate','/ɪnˈstænʃieɪt/','verb','구현하다, 사례로 나타내다','To represent an abstract concept by means of a concrete example.','This case study {instantiate}s the theory.','이 사례 연구가 이론을 구현합니다.','instantiate','C2','presentation',2,'instantiate example concrete theory case study prove'),
('w_presentation_C2_30','probative','/ˈproʊbətɪv/','adjective','증명력 있는','Having the quality of proving or demonstrating something.','Only {probative} evidence was considered.','증명력 있는 증거만 고려되었습니다.','probative','C2','presentation',2,'probative evidence proof demonstrate quality strong'),
('w_presentation_C2_31','circumlocution','/ˌsɜːrkəmloʊˈkjuːʃən/','noun','우회적 표현','The use of many words where fewer would be clear; indirect expression.','Avoid {circumlocution} to maintain audience attention.','청중의 집중을 유지하려면 우회적 표현을 피하세요.','circumlocution','C2','presentation',2,'circumlocution indirect wordy verbose clarity brevity'),
('w_presentation_C2_32','apophenia','/ˌæpəˈfiːniə/','noun','패턴 착각 현상','The tendency to perceive meaningful connections between unrelated things.','Analysts must guard against {apophenia} in data.','분석가는 데이터의 패턴 착각을 경계해야 합니다.','apophenia','C2','presentation',2,'apophenia false pattern bias data analysis error'),
('w_presentation_C2_33','episteme','/ˈepɪˌstiːm/','noun','에피스테메','The body of ideas that define the knowledge of a particular era.','The dominant {episteme} shapes how data is framed.','지배적인 에피스테메가 데이터가 구성되는 방식을 형성합니다.','episteme','C2','presentation',2,'episteme knowledge era framework Foucault paradigm'),
('w_presentation_C2_34','isomorphism','/ˈaɪsəˌmɔːrfɪzəm/','noun','동형성','A correspondence or similarity in form or structure between two models.','There is an {isomorphism} between the two models.','두 모델 사이에 동형성이 있습니다.','isomorphism','C2','presentation',2,'isomorphism same structure parallel model comparison'),
('w_presentation_C2_35','polysemy','/pɒˈlɪsɪmi/','noun','다의성','The capacity of a word or phrase to have multiple meanings.','{Polysemy} in technical terms can confuse audiences.','기술 용어의 다의성은 청중을 혼란스럽게 할 수 있습니다.','polysemy','C2','presentation',2,'polysemy multiple meanings ambiguity language precision');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A1_01','want','/wɒnt/','verb','원하다','To feel a desire or wish for something.','What do you {want} from this deal?','이 거래에서 무엇을 원하세요?','want','A1','negotiation',1,'negotiation business handshake agreement'),
('w_negotiation_A1_02','need','/niːd/','verb','필요하다','To require something as necessary or important.','I {need} a better price for this.','이것에 더 좋은 가격이 필요해요.','need','A1','negotiation',1,'need requirement checklist office'),
('w_negotiation_A1_03','give','/ɡɪv/','verb','주다','To hand something over to someone.','Can you {give} me a small discount?','할인을 조금 주실 수 있나요?','give','A1','negotiation',1,'giving handshake gift exchange'),
('w_negotiation_A1_04','take','/teɪk/','verb','받아들이다, 가져가다','To accept something that is offered.','I''ll {take} the offer if the price is right.','가격이 맞으면 제안을 받아들일게요.','take','A1','negotiation',1,'accept deal take offer business'),
('w_negotiation_A1_05','agree','/əˈɡriː/','verb','동의하다','To have the same opinion as someone else.','We both {agree} on the main points.','우리는 주요 사항에 동의해요.','agree','A1','negotiation',1,'agreement nodding handshake smiling'),
('w_negotiation_A1_06','ask','/ɑːsk/','verb','요청하다, 묻다','To request something or seek information.','I want to {ask} for a longer deadline.','더 긴 마감일을 요청하고 싶어요.','ask','A1','negotiation',1,'question asking office meeting discussion'),
('w_negotiation_A1_07','offer','/ˈɒfər/','verb','제안하다','To present something for someone to accept or refuse.','We can {offer} a better rate next month.','다음 달에 더 좋은 요율을 제안할 수 있어요.','offer','A1','negotiation',1,'offer proposal business meeting table'),
('w_negotiation_A1_08','deal','/diːl/','noun','거래, 합의','An agreement, especially in business.','We made a great {deal} with the supplier.','공급업체와 좋은 거래를 했어요.','deal','A1','negotiation',1,'business deal handshake contract signing'),
('w_negotiation_A1_09','yes','/jes/','adverb','네, 예','Used to give an affirmative answer or agreement.','Say {yes} only when you are ready.','준비가 됐을 때만 예스라고 하세요.','yes','A1','negotiation',1,'agreement thumbs up approval positive'),
('w_negotiation_A1_10','no','/nəʊ/','adverb','아니요','Used to give a negative answer or refusal.','It is okay to say {no} in a negotiation.','협상에서 아니오라고 해도 괜찮아요.','no','A1','negotiation',1,'refusal shaking head no disagreement'),
('w_negotiation_A1_11','help','/help/','verb','돕다','To make it easier for someone to do something.','Can you {help} me with the contract?','계약서 작성을 도와주실 수 있나요?','help','A1','negotiation',1,'helping colleague office teamwork support'),
('w_negotiation_A1_12','more','/mɔːr/','adverb','더','A greater quantity or amount.','I need {more} time to think about it.','생각할 시간이 더 필요해요.','more','A1','negotiation',2,'more quantity increase growth chart'),
('w_negotiation_A1_13','less','/les/','adverb','덜, 더 적게','A smaller quantity or degree.','Can we pay {less} than the asking price?','요구 가격보다 덜 낼 수 있을까요?','less','A1','negotiation',2,'reduce decrease lower price tag'),
('w_negotiation_A1_14','pay','/peɪ/','verb','지불하다','To give money for goods or services.','How much do we need to {pay} upfront?','선불로 얼마나 내야 하나요?','pay','A1','negotiation',1,'payment money cash credit card'),
('w_negotiation_A1_15','get','/ɡet/','verb','얻다','To obtain or receive something.','What do we {get} in return?','대신 우리는 무엇을 얻나요?','get','A1','negotiation',1,'receive obtain reward benefit'),
('w_negotiation_A1_16','talk','/tɔːk/','verb','이야기하다','To communicate by speaking.','Let''s {talk} about the details later.','나중에 세부 사항에 대해 이야기해요.','talk','A1','negotiation',2,'conversation talking office meeting people'),
('w_negotiation_A1_17','meet','/miːt/','verb','만나다','To come together with someone at a place.','Can we {meet} on Friday to discuss this?','이것을 논의하기 위해 금요일에 만날 수 있나요?','meet','A1','negotiation',2,'meeting handshake conference room business'),
('w_negotiation_A1_18','say','/seɪ/','verb','말하다','To express something in words.','Please {say} what you think clearly.','생각하시는 것을 명확히 말씀해 주세요.','say','A1','negotiation',2,'speaking talking presentation clear communication'),
('w_negotiation_A1_19','wait','/weɪt/','verb','기다리다','To stay in one place until something happens.','Please {wait} while I check the numbers.','숫자를 확인하는 동안 기다려 주세요.','wait','A1','negotiation',2,'waiting patience calm office'),
('w_negotiation_A1_20','try','/traɪ/','verb','시도하다','To make an effort to do something.','Let''s {try} to find a middle ground.','중간 지점을 찾아보도록 해요.','try','A1','negotiation',2,'effort attempt trying problem solving'),
('w_negotiation_A1_21','buy','/baɪ/','verb','구매하다','To get something by paying money for it.','We want to {buy} in bulk to lower the price.','가격을 낮추기 위해 대량으로 구매하고 싶어요.','buy','A1','negotiation',1,'purchasing buying store bulk shopping'),
('w_negotiation_A1_22','sell','/sel/','verb','팔다','To give something in exchange for money.','We can {sell} at this price if you order now.','지금 주문하시면 이 가격에 드릴 수 있어요.','sell','A1','negotiation',1,'selling business commerce sale market'),
('w_negotiation_A1_23','price','/praɪs/','noun','가격','The amount of money expected for something.','What is the best {price} you can offer?','가장 좋은 가격은 얼마인가요?','price','A1','negotiation',1,'price tag label shopping market cost'),
('w_negotiation_A1_24','time','/taɪm/','noun','시간','A period within which something is done.','Do we have enough {time} to review everything?','모든 것을 검토할 시간이 충분한가요?','time','A1','negotiation',2,'clock time management deadline calendar'),
('w_negotiation_A1_25','good','/ɡʊd/','adjective','좋은','Of high quality or beneficial.','That sounds like a {good} offer to me.','저에게는 좋은 제안처럼 들려요.','good','A1','negotiation',2,'quality good positive thumbs up'),
('w_negotiation_A1_26','bad','/bæd/','adjective','나쁜','Of poor quality or unfavorable.','The terms are too {bad} to accept right now.','지금 당장 받아들이기엔 조건이 너무 나빠요.','bad','A1','negotiation',2,'negative poor quality unhappy'),
('w_negotiation_A1_27','okay','/ˌəʊˈkeɪ/','adjective','괜찮은','Satisfactory but not excellent.','The first offer is {okay} but we need more.','첫 제안은 괜찮지만 더 필요해요.','okay','A1','negotiation',2,'okay agreement acceptable neutral'),
('w_negotiation_A1_28','change','/tʃeɪndʒ/','verb','바꾸다','To make something different.','Can we {change} the payment schedule?','지불 일정을 바꿀 수 있을까요?','change','A1','negotiation',2,'change adjust modify edit revise'),
('w_negotiation_A1_29','stop','/stɒp/','verb','멈추다','To cease doing something.','Let''s {stop} here and continue tomorrow.','여기서 멈추고 내일 계속해요.','stop','A1','negotiation',3,'stop pause break rest meeting'),
('w_negotiation_A1_30','start','/stɑːt/','verb','시작하다','To begin something.','Let''s {start} with the most important issue.','가장 중요한 사안부터 시작해요.','start','A1','negotiation',2,'start begin launch opening meeting'),
('w_negotiation_A1_31','ready','/ˈredi/','adjective','준비된','Prepared and able to do something.','Are you {ready} to make a final decision?','최종 결정을 내릴 준비가 됐나요?','ready','A1','negotiation',2,'ready prepared confident business person'),
('w_negotiation_A1_32','open','/ˈəʊpən/','adjective','열린, 개방적인','Willing to consider new ideas.','I am {open} to other suggestions.','다른 제안에 열려 있어요.','open','A1','negotiation',2,'open door opportunity discussion flexible'),
('w_negotiation_A1_33','right','/raɪt/','adjective','맞는, 올바른','Correct or appropriate.','We need to find the {right} solution for both sides.','양쪽에 맞는 해결책을 찾아야 해요.','right','A1','negotiation',2,'correct right check mark solution'),
('w_negotiation_A1_34','work','/wɜːk/','verb','효과가 있다','To function effectively or be successful.','This plan can {work} if we cooperate.','협력하면 이 계획은 효과가 있을 거예요.','work','A1','negotiation',2,'teamwork cooperation plan effective'),
('w_negotiation_A1_35','think','/θɪŋk/','verb','생각하다','To use your mind to consider something.','Let me {think} about it and get back to you.','생각해 보고 다시 연락할게요.','think','A1','negotiation',2,'thinking considering person office pause');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_A2_01','discount','/ˈdɪskaʊnt/','noun','할인','A reduction in the usual price of something.','Can you offer a {discount} for a large order?','대량 주문에 할인을 해주실 수 있나요?','discount','A2','negotiation',1,'discount sale percentage tag price reduction'),
('w_negotiation_A2_02','accept','/əkˈsept/','verb','받아들이다','To agree to receive or take something offered.','We are happy to {accept} the revised terms.','수정된 조건을 기꺼이 받아들여요.','accept','A2','negotiation',1,'accept agreement handshake deal approval'),
('w_negotiation_A2_03','refuse','/rɪˈfjuːz/','verb','거절하다','To say that you will not do or accept something.','We have to {refuse} the current proposal.','현재 제안은 거절해야 해요.','refuse','A2','negotiation',1,'refuse reject decline shake head no'),
('w_negotiation_A2_04','propose','/prəˈpəʊz/','verb','제안하다','To put forward a plan or idea for consideration.','I would like to {propose} a new payment plan.','새로운 지불 계획을 제안하고 싶어요.','propose','A2','negotiation',1,'propose idea presentation whiteboard business'),
('w_negotiation_A2_05','condition','/kənˈdɪʃən/','noun','조건','A requirement that must be met before something can happen.','What are the main {conditions} of the agreement?','계약의 주요 조건은 무엇인가요?','condition','A2','negotiation',1,'conditions checklist contract terms document'),
('w_negotiation_A2_06','term','/tɜːm/','noun','조건, 기간','A condition or stipulation in a contract or agreement.','The payment {terms} are thirty days net.','지불 조건은 순 30일이에요.','term','A2','negotiation',1,'terms contract document signing office'),
('w_negotiation_A2_07','fair','/feər/','adjective','공정한','Treating everyone equally and according to the rules.','We want a {fair} deal for both sides.','양쪽 모두에게 공정한 거래를 원해요.','fair','A2','negotiation',1,'fair balance scales justice equal'),
('w_negotiation_A2_08','both','/bəʊθ/','determiner','둘 다','Two people or things considered together.','This outcome benefits {both} parties.','이 결과는 양 당사자 모두에게 이익이에요.','both','A2','negotiation',2,'both sides together partnership balance'),
('w_negotiation_A2_09','together','/təˈɡeðər/','adverb','함께','With each other; in cooperation.','Let''s work {together} on the final contract.','최종 계약서를 함께 작업해요.','together','A2','negotiation',2,'teamwork together partnership cooperation office'),
('w_negotiation_A2_10','budget','/ˈbʌdʒɪt/','noun','예산','The amount of money available for a purpose.','Our {budget} does not allow for that increase.','우리 예산으로는 그 인상을 허용할 수 없어요.','budget','A2','negotiation',1,'budget finance spreadsheet planning money'),
('w_negotiation_A2_11','payment','/ˈpeɪmənt/','noun','지불, 결제','The act of paying money owed.','Can we split the {payment} into installments?','지불을 할부로 나눌 수 있나요?','payment','A2','negotiation',1,'payment credit card invoice receipt'),
('w_negotiation_A2_12','delivery','/dɪˈlɪvəri/','noun','배송, 납품','The process of bringing goods to a buyer.','We need faster {delivery} dates to meet demand.','수요를 맞추려면 더 빠른 납품 날짜가 필요해요.','delivery','A2','negotiation',1,'delivery shipping logistics package truck'),
('w_negotiation_A2_13','contract','/ˈkɒntrækt/','noun','계약서','A written legal agreement between parties.','Please review the {contract} before signing.','서명 전에 계약서를 검토해 주세요.','contract','A2','negotiation',1,'contract document signing pen legal'),
('w_negotiation_A2_14','agree on','/əˈɡriː ɒn/','phrase','~에 합의하다','To reach a shared decision about something.','We need to {agree on} a final price today.','오늘 최종 가격에 합의해야 해요.','agree on','A2','negotiation',1,'agreement consensus handshake decision'),
('w_negotiation_A2_15','total','/ˈtəʊtəl/','noun','총액','The whole amount or sum.','The {total} cost comes to five thousand dollars.','총 비용은 5,000달러예요.','total','A2','negotiation',1,'total sum calculator invoice finance'),
('w_negotiation_A2_16','flexible','/ˈfleksɪbəl/','adjective','유연한','Willing to change to suit new conditions.','Are you {flexible} on the delivery date?','납품 날짜에 유연성이 있나요?','flexible','A2','negotiation',2,'flexible adjustable adaptable options choice'),
('w_negotiation_A2_17','option','/ˈɒpʃən/','noun','선택지','A thing that is or may be chosen.','We have several {options} to discuss.','논의할 선택지가 몇 가지 있어요.','option','A2','negotiation',1,'options choices multiple decision paths'),
('w_negotiation_A2_18','cost','/kɒst/','noun','비용','The amount paid to buy or produce something.','The {cost} of shipping needs to be reduced.','배송 비용을 줄여야 해요.','cost','A2','negotiation',1,'cost expense money calculation finance'),
('w_negotiation_A2_19','question','/ˈkwɛstʃən/','noun','질문','A sentence requesting information.','I have one important {question} about the terms.','조건에 관해 중요한 질문이 하나 있어요.','question','A2','negotiation',2,'question inquiry thinking meeting discussion'),
('w_negotiation_A2_20','reduce','/rɪˈdjuːs/','verb','줄이다','To make something smaller or less.','Could you {reduce} the minimum order quantity?','최소 주문 수량을 줄여주실 수 있나요?','reduce','A2','negotiation',1,'reduce decrease lower cut graph'),
('w_negotiation_A2_21','increase','/ɪnˈkriːs/','verb','늘리다','To become or make something greater.','We plan to {increase} our order next quarter.','다음 분기에 주문을 늘릴 계획이에요.','increase','A2','negotiation',2,'increase growth chart upward business'),
('w_negotiation_A2_22','include','/ɪnˈkluːd/','verb','포함하다','To have something as part of a whole.','Does the price {include} installation costs?','가격에 설치 비용이 포함되나요?','include','A2','negotiation',2,'include checklist package contents all'),
('w_negotiation_A2_23','consider','/kənˈsɪdər/','verb','고려하다','To think carefully about something.','Please {consider} our revised offer.','수정된 제안을 고려해 주세요.','consider','A2','negotiation',1,'consider thinking review evaluate option'),
('w_negotiation_A2_24','sample','/ˈsæmpəl/','noun','샘플','A small part or quantity that shows what the whole is like.','Could you send a {sample} before we decide?','결정하기 전에 샘플을 보내주실 수 있나요?','sample','A2','negotiation',2,'sample product test quality review'),
('w_negotiation_A2_25','schedule','/ˈskedʒuːl/','noun','일정','A plan of things to be done at specific times.','Let''s set a {schedule} for the next steps.','다음 단계를 위한 일정을 정해요.','schedule','A2','negotiation',2,'schedule calendar planning timeline meeting'),
('w_negotiation_A2_26','confirm','/kənˈfɜːm/','verb','확인하다','To make something certain or definite.','Please {confirm} your acceptance by email.','이메일로 수락을 확인해 주세요.','confirm','A2','negotiation',1,'confirm check approve email agreement'),
('w_negotiation_A2_27','cancel','/ˈkænsəl/','verb','취소하다','To decide not to proceed with a plan.','We may have to {cancel} if terms do not improve.','조건이 개선되지 않으면 취소해야 할 수도 있어요.','cancel','A2','negotiation',2,'cancel stop halt exit plan'),
('w_negotiation_A2_28','extra','/ˈekstrə/','adjective','추가의','More than what is usual or expected.','Are there any {extra} fees we should know about?','알아야 할 추가 요금이 있나요?','extra','A2','negotiation',2,'extra additional fees hidden costs'),
('w_negotiation_A2_29','limit','/ˈlɪmɪt/','noun','한도, 제한','The highest amount of something allowed.','There is a {limit} to what we can offer.','우리가 제공할 수 있는 것에 한도가 있어요.','limit','A2','negotiation',2,'limit boundary maximum cap constraint'),
('w_negotiation_A2_30','expect','/ɪkˈspekt/','verb','기대하다','To believe something will happen.','We {expect} delivery within two weeks.','2주 내에 배송을 기대해요.','expect','A2','negotiation',2,'expect anticipate timeline delivery business'),
('w_negotiation_A2_31','check','/tʃek/','verb','확인하다','To examine something to ensure it is correct.','Let me {check} with my manager first.','먼저 매니저와 확인해 볼게요.','check','A2','negotiation',2,'check verify review approve manager'),
('w_negotiation_A2_32','invoice','/ˈɪnvɔɪs/','noun','청구서, 인보이스','A document listing goods or services provided and their cost.','Please send the {invoice} to our accounts department.','회계 부서로 청구서를 보내주세요.','invoice','A2','negotiation',1,'invoice receipt billing payment document'),
('w_negotiation_A2_33','guarantee','/ˌɡærənˈtiː/','noun','보장, 보증','A formal assurance that certain conditions will be met.','Can you {guarantee} delivery by Monday?','월요일까지 배송을 보장해주실 수 있나요?','guarantee','A2','negotiation',1,'guarantee warranty promise assurance certificate'),
('w_negotiation_A2_34','review','/rɪˈvjuː/','verb','검토하다','To examine something in detail to assess it.','We will {review} the proposal and respond tomorrow.','제안서를 검토하고 내일 답변드릴게요.','review','A2','negotiation',1,'review document reading analysis office'),
('w_negotiation_A2_35','meeting','/ˈmiːtɪŋ/','noun','회의','A gathering of people for discussion.','Can we set up a {meeting} to finalize the details?','세부 사항을 확정하기 위한 회의를 잡을 수 있나요?','meeting','A2','negotiation',1,'meeting conference room business discussion table');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B1_01','negotiate','/nɪˈɡəʊʃieɪt/','verb','협상하다','To discuss formally to reach an agreement.','Both sides agreed to {negotiate} a new contract.','양측은 새로운 계약을 협상하기로 합의했어요.','negotiate','B1','negotiation',1,'negotiate discussion business meeting formal'),
('w_negotiation_B1_02','compromise','/ˈkɒmprəmaɪz/','verb','타협하다','To settle by mutual concession; accept less than ideal.','We had to {compromise} on the delivery schedule.','납품 일정에 대해 타협해야 했어요.','compromise','B1','negotiation',1,'compromise balance middle ground agreement'),
('w_negotiation_B1_03','concession','/kənˈseʃən/','noun','양보','A thing granted as a compromise.','Making a small {concession} helped close the deal.','작은 양보가 거래를 성사시키는 데 도움이 됐어요.','concession','B1','negotiation',1,'concession compromise giving yielding negotiation'),
('w_negotiation_B1_04','leverage','/ˈlevərɪdʒ/','noun','협상력, 레버리지','Power or advantage used to achieve a goal.','Our bulk order gives us strong {leverage}.','대량 주문이 우리에게 강한 협상력을 줘요.','leverage','B1','negotiation',1,'leverage power advantage business strategy'),
('w_negotiation_B1_05','counterproposal','/ˌkaʊntərprəˈpəʊzəl/','noun','역제안','An offer made in response to one that is unacceptable.','They submitted a {counterproposal} the next day.','그들은 다음 날 역제안을 제출했어요.','counterproposal','B1','negotiation',1,'counter offer response proposal meeting'),
('w_negotiation_B1_06','deadline','/ˈdedlaɪn/','noun','마감일','The latest time by which something must be finished.','The contract {deadline} is the end of this month.','계약 마감일은 이번 달 말이에요.','deadline','B1','negotiation',1,'deadline calendar clock urgency date'),
('w_negotiation_B1_07','stakeholder','/ˈsteɪkhəʊldər/','noun','이해관계자','A person with an interest or concern in a project.','All {stakeholders} must approve the final terms.','모든 이해관계자가 최종 조건을 승인해야 해요.','stakeholder','B1','negotiation',1,'stakeholder group meeting board approval'),
('w_negotiation_B1_08','agenda','/əˈdʒendə/','noun','의제, 안건','A list of matters to be discussed at a meeting.','Let''s stick to the {agenda} and focus on pricing.','의제를 지키고 가격에 집중해요.','agenda','B1','negotiation',1,'agenda meeting list discussion items'),
('w_negotiation_B1_09','clause','/klɔːz/','noun','조항','A particular section or condition in a contract.','The penalty {clause} needs to be revised.','위약금 조항을 수정해야 해요.','clause','B1','negotiation',1,'clause contract legal document section'),
('w_negotiation_B1_10','binding','/ˈbaɪndɪŋ/','adjective','법적 구속력이 있는','Legally required to be carried out.','Once signed, this agreement is {binding} on both parties.','서명 후, 이 계약은 양 당사자에게 법적 구속력이 생겨요.','binding','B1','negotiation',1,'binding contract legal signature document'),
('w_negotiation_B1_11','mutual','/ˈmjuːtʃuəl/','adjective','상호의','Felt or done by two parties equally.','We need to reach a {mutual} understanding first.','먼저 상호 이해에 도달해야 해요.','mutual','B1','negotiation',1,'mutual agreement both sides understanding'),
('w_negotiation_B1_12','transparent','/trænsˈpærənt/','adjective','투명한','Open and honest; not hiding anything.','Please be {transparent} about all associated costs.','모든 관련 비용에 대해 투명하게 밝혀주세요.','transparent','B1','negotiation',1,'transparent honesty glass clear open'),
('w_negotiation_B1_13','position','/pəˈzɪʃən/','noun','입장, 포지션','A viewpoint or stance in a discussion.','Our {position} is firm on the minimum quantity.','최소 수량에 대한 우리의 입장은 확고해요.','position','B1','negotiation',1,'position stance viewpoint discussion negotiation'),
('w_negotiation_B1_14','alternative','/ɔːlˈtɜːnətɪv/','noun','대안','A different or new choice.','Is there an {alternative} to the current plan?','현재 계획에 대한 대안이 있나요?','alternative','B1','negotiation',1,'alternative option choice path direction'),
('w_negotiation_B1_15','penalty','/ˈpenəlti/','noun','위약금, 벌칙','A punishment for breaking a rule or contract.','There is a 10% {penalty} for late delivery.','납품 지연 시 10% 위약금이 있어요.','penalty','B1','negotiation',1,'penalty fine clause contract legal'),
('w_negotiation_B1_16','objective','/əbˈdʒektɪv/','noun','목표, 목적','A goal or aim to be achieved.','Our main {objective} is to reduce total cost.','우리의 주요 목표는 총 비용을 줄이는 것이에요.','objective','B1','negotiation',2,'objective goal target planning strategy'),
('w_negotiation_B1_17','priority','/praɪˈɒrɪti/','noun','우선순위','The level of importance given to something.','Price is our top {priority} in this deal.','가격이 이 거래에서 우리의 최우선순위예요.','priority','B1','negotiation',1,'priority ranking importance list order'),
('w_negotiation_B1_18','revision','/rɪˈvɪʒən/','noun','수정, 개정','An amended version of something.','We submitted a {revision} of the original draft.','원본 초안의 수정본을 제출했어요.','revision','B1','negotiation',2,'revision edit document update change'),
('w_negotiation_B1_19','finalize','/ˈfaɪnəlaɪz/','verb','마무리하다','To complete or settle a plan or agreement.','We hope to {finalize} the deal by Friday.','금요일까지 거래를 마무리하길 바라요.','finalize','B1','negotiation',1,'finalize complete done stamp approval'),
('w_negotiation_B1_20','dispute','/dɪˈspjuːt/','noun','분쟁','A disagreement or argument between parties.','A {dispute} over payment terms caused delays.','지불 조건에 관한 분쟁이 지연을 야기했어요.','dispute','B1','negotiation',1,'dispute disagreement conflict resolution'),
('w_negotiation_B1_21','proposal','/prəˈpəʊzəl/','noun','제안서','A formal plan or suggestion.','Please read our {proposal} before the meeting.','회의 전에 우리 제안서를 읽어주세요.','proposal','B1','negotiation',1,'proposal document presentation business plan'),
('w_negotiation_B1_22','timeline','/ˈtaɪmlaɪn/','noun','일정표, 타임라인','A schedule showing events in order of time.','The project {timeline} needs to be agreed upon.','프로젝트 타임라인에 합의해야 해요.','timeline','B1','negotiation',2,'timeline schedule project management chart'),
('w_negotiation_B1_23','scope','/skəʊp/','noun','범위, 영역','The range or extent of something.','We need to define the {scope} of the project first.','먼저 프로젝트의 범위를 정의해야 해요.','scope','B1','negotiation',2,'scope range boundary definition project'),
('w_negotiation_B1_24','approve','/əˈpruːv/','verb','승인하다','To officially agree to something.','The board will {approve} the contract next week.','이사회가 다음 주에 계약을 승인할 거예요.','approve','B1','negotiation',1,'approve signature stamp official decision'),
('w_negotiation_B1_25','negotiate down','/nɪˈɡəʊʃieɪt daʊn/','phrase','가격을 낮추다','To successfully reduce a price through discussion.','We managed to {negotiate down} the setup fee.','설치 비용을 낮추는 데 성공했어요.','negotiate down','B1','negotiation',2,'price reduction negotiation bargain lower'),
('w_negotiation_B1_26','obligation','/ˌɒblɪˈɡeɪʃən/','noun','의무','A duty or commitment required by a contract.','Both parties have clear {obligations} under this deal.','양 당사자는 이 거래에서 명확한 의무가 있어요.','obligation','B1','negotiation',1,'obligation duty responsibility commitment'),
('w_negotiation_B1_27','benchmark','/ˈbentʃmɑːk/','noun','기준, 벤치마크','A standard to compare against when evaluating something.','Let''s use the market rate as a {benchmark}.','시장 가격을 기준으로 삼아요.','benchmark','B1','negotiation',2,'benchmark standard comparison market analysis'),
('w_negotiation_B1_28','volume','/ˈvɒljuːm/','noun','물량, 규모','The amount or quantity of something.','Higher {volume} orders qualify for a bigger discount.','더 큰 물량 주문은 더 큰 할인 자격이 돼요.','volume','B1','negotiation',1,'volume quantity bulk order warehouse'),
('w_negotiation_B1_29','in writing','/ɪn ˈraɪtɪŋ/','phrase','서면으로','Recorded as a written document.','All changes must be confirmed {in writing}.','모든 변경 사항은 서면으로 확인해야 해요.','in writing','B1','negotiation',1,'writing document formal letter official'),
('w_negotiation_B1_30','exclusive','/ɪkˈskluːsɪv/','adjective','독점적인','Restricted to a single entity; not shared.','We want an {exclusive} distribution agreement.','독점 유통 계약을 원해요.','exclusive','B1','negotiation',2,'exclusive VIP premium restricted access'),
('w_negotiation_B1_31','minimum','/ˈmɪnɪməm/','noun','최소','The smallest amount or level possible.','The {minimum} order is five hundred units.','최소 주문은 500개예요.','minimum','B1','negotiation',2,'minimum baseline floor limit quantity'),
('w_negotiation_B1_32','extension','/ɪkˈstenʃən/','noun','연장','An increase in the length of time allowed.','We need a two-week {extension} on the deadline.','마감일을 2주 연장해야 해요.','extension','B1','negotiation',2,'extension time deadline extra period calendar'),
('w_negotiation_B1_33','headroom','/ˈhedrʊm/','noun','협상 여지','Room or space available for negotiation or movement.','There is very little {headroom} left on the price.','가격에 협상 여지가 거의 없어요.','headroom','B1','negotiation',2,'space room margin flexibility negotiation'),
('w_negotiation_B1_34','walk away','/wɔːk əˈweɪ/','phrase','협상에서 물러나다','To leave a negotiation without reaching agreement.','We are prepared to {walk away} if terms worsen.','조건이 나빠지면 물러날 준비가 돼 있어요.','walk away','B1','negotiation',1,'walk away exit leave negotiation table'),
('w_negotiation_B1_35','penalty clause','/ˈpenəlti klɔːz/','phrase','위약금 조항','A clause specifying punishment for failing obligations.','The {penalty clause} protects both parties.','위약금 조항은 양 당사자를 보호해요.','penalty clause','B1','negotiation',1,'penalty clause contract protection legal');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_B2_01','arbitration','/ˌɑːbɪˈtreɪʃən/','noun','중재','A method of resolving disputes outside the courts.','The contract includes an {arbitration} clause.','계약서에 중재 조항이 포함돼 있어요.','arbitration','B2','negotiation',1,'arbitration mediation dispute resolution legal'),
('w_negotiation_B2_02','mediation','/ˌmiːdiˈeɪʃən/','noun','조정, 중재','Intervention to settle a dispute between parties.','{Mediation} is often faster than litigation.','조정은 소송보다 종종 빠릅니다.','mediation','B2','negotiation',1,'mediation neutral third party dispute settlement'),
('w_negotiation_B2_03','litigation','/ˌlɪtɪˈɡeɪʃən/','noun','소송','The process of taking legal action in court.','We want to avoid {litigation} at all costs.','어떤 대가를 치르더라도 소송을 피하고 싶어요.','litigation','B2','negotiation',1,'litigation court lawsuit legal process judge'),
('w_negotiation_B2_04','liability','/ˌlaɪəˈbɪlɪti/','noun','책임, 배상 책임','Legal responsibility for something, especially damage or debt.','The contract limits our {liability} to direct damages.','계약은 우리의 책임을 직접 손해로 제한해요.','liability','B2','negotiation',1,'liability responsibility legal risk insurance'),
('w_negotiation_B2_05','indemnity','/ɪnˈdemnɪti/','noun','보상, 면책','Compensation for harm or loss; exemption from liability.','We require full {indemnity} against third-party claims.','제3자 청구에 대한 완전한 면책이 필요해요.','indemnity','B2','negotiation',1,'indemnity compensation protection insurance contract'),
('w_negotiation_B2_06','warranty','/ˈwɒrənti/','noun','보증, 품질보증','A written guarantee for the quality of a product.','The equipment comes with a two-year {warranty}.','장비에는 2년 보증이 포함돼 있어요.','warranty','B2','negotiation',1,'warranty guarantee certificate product quality'),
('w_negotiation_B2_07','escrow','/ˈeskrəʊ/','noun','에스크로 (제3자 보관)','Money held by a third party until conditions are met.','Payment will be held in {escrow} until delivery.','배송될 때까지 지불금은 에스크로에 보관돼요.','escrow','B2','negotiation',1,'escrow third party trust account secure payment'),
('w_negotiation_B2_08','contingency','/kənˈtɪndʒənsi/','noun','예비 조항, 우발 상황','A provision for a possible future event or circumstance.','Add a {contingency} clause for force majeure events.','불가항력 사태에 대한 예비 조항을 추가해요.','contingency','B2','negotiation',1,'contingency plan backup risk management scenario'),
('w_negotiation_B2_09','ratify','/ˈrætɪfaɪ/','verb','비준하다, 공식 승인하다','To formally confirm or approve a contract.','Both boards must {ratify} the agreement.','양 이사회가 합의를 공식 승인해야 해요.','ratify','B2','negotiation',1,'ratify approve formal sign official stamp'),
('w_negotiation_B2_10','void','/vɔɪd/','adjective','무효인','Not legally binding or enforceable.','A contract signed under duress may be {void}.','강요 하에 서명된 계약은 무효일 수 있어요.','void','B2','negotiation',1,'void invalid null cancelled contract legal'),
('w_negotiation_B2_11','force majeure','/ˌfɔːs mæˈʒɜːr/','noun','불가항력','Unforeseeable circumstances preventing contract fulfilment.','The flood triggered the {force majeure} clause.','홍수로 인해 불가항력 조항이 발동됐어요.','force majeure','B2','negotiation',1,'force majeure disaster unpredictable event clause'),
('w_negotiation_B2_12','confidentiality','/ˌkɒnfɪˌdenʃiˈælɪti/','noun','기밀성','The state of keeping information secret.','Both parties must sign a {confidentiality} agreement.','양 당사자는 기밀 유지 계약에 서명해야 해요.','confidentiality','B2','negotiation',1,'confidentiality NDA secret agreement privacy'),
('w_negotiation_B2_13','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권','The authority of a court or territory to hear a legal case.','This contract falls under Korean {jurisdiction}.','이 계약은 한국 관할권에 속해요.','jurisdiction','B2','negotiation',1,'jurisdiction court authority territory legal system'),
('w_negotiation_B2_14','amendment','/əˈmendmənt/','noun','수정안','A formal change made to a document or law.','We propose an {amendment} to the payment schedule.','지불 일정에 대한 수정안을 제안해요.','amendment','B2','negotiation',1,'amendment change revision document formal'),
('w_negotiation_B2_15','breach','/briːtʃ/','noun','위반','A failure to keep a contract or obligation.','Late delivery constitutes a {breach} of contract.','납품 지연은 계약 위반에 해당해요.','breach','B2','negotiation',1,'breach violation contract failure legal'),
('w_negotiation_B2_16','enforceable','/ɪnˈfɔːrsəbəl/','adjective','집행 가능한','Capable of being legally put into effect.','The clause is only {enforceable} if notarized.','조항은 공증된 경우에만 집행 가능해요.','enforceable','B2','negotiation',2,'enforceable legal binding official court'),
('w_negotiation_B2_17','non-disclosure','/nɒn dɪsˈkləʊʒər/','noun','비공개, 비밀 유지','The action of not revealing confidential information.','Sign the {non-disclosure} agreement before the demo.','데모 전에 비밀 유지 계약서에 서명해주세요.','non-disclosure','B2','negotiation',1,'non-disclosure NDA secret confidential agreement'),
('w_negotiation_B2_18','indemnify','/ɪnˈdemnɪfaɪ/','verb','면책하다, 보상하다','To compensate for harm or protect against legal liability.','We agree to {indemnify} you against all claims.','모든 청구에 대해 면책해 드리기로 동의해요.','indemnify','B2','negotiation',1,'indemnify compensate protect legal insurance'),
('w_negotiation_B2_19','milestone','/ˈmaɪlstəʊn/','noun','이정표, 중요 단계','A significant point in the development of something.','Payment is tied to each project {milestone}.','지불은 각 프로젝트 이정표에 연동돼요.','milestone','B2','negotiation',2,'milestone progress achievement project completion'),
('w_negotiation_B2_20','exclusivity','/ˌɪkskluːˈsɪvɪti/','noun','독점권','The state of being available to only one party.','We request {exclusivity} in the Korean market.','한국 시장에서의 독점권을 요청해요.','exclusivity','B2','negotiation',1,'exclusivity exclusive rights territory market'),
('w_negotiation_B2_21','termination','/ˌtɜːrmɪˈneɪʃən/','noun','해지, 종료','The ending of a contract or agreement.','Either party may trigger {termination} with notice.','어느 쪽이든 통보로 해지를 개시할 수 있어요.','termination','B2','negotiation',1,'termination end contract closure notice period'),
('w_negotiation_B2_22','representation','/ˌreprɪzenˈteɪʃən/','noun','진술, 대리','A statement made to induce someone to enter a contract.','Their {representations} proved to be inaccurate.','그들의 진술이 부정확한 것으로 드러났어요.','representation','B2','negotiation',2,'representation statement legal contract claim'),
('w_negotiation_B2_23','due diligence','/djuː ˈdɪlɪdʒəns/','noun','실사, 적법한 조사','A thorough investigation before signing a contract.','We will conduct {due diligence} over two weeks.','2주 동안 실사를 진행할 거예요.','due diligence','B2','negotiation',1,'due diligence investigation research audit legal'),
('w_negotiation_B2_24','indemnification','/ɪnˌdemnɪfɪˈkeɪʃən/','noun','손해 배상, 면책','The act of providing compensation for loss or damage.','The {indemnification} clause covers third-party claims.','면책 조항은 제3자 청구를 포함해요.','indemnification','B2','negotiation',1,'indemnification clause protection legal compensation'),
('w_negotiation_B2_25','governing law','/ˈɡʌvənɪŋ lɔː/','noun','준거법','The law that governs the interpretation of a contract.','The {governing law} for this contract is English law.','이 계약의 준거법은 영국법이에요.','governing law','B2','negotiation',1,'governing law jurisdiction legal contract'),
('w_negotiation_B2_26','consideration','/kənˌsɪdəˈreɪʃən/','noun','대가, 약인','Something of value exchanged to make a contract valid.','Adequate {consideration} is required for a valid contract.','유효한 계약에는 적절한 대가가 필요해요.','consideration','B2','negotiation',1,'consideration value exchange contract legal'),
('w_negotiation_B2_27','severability','/sɪˌverəˈbɪlɪti/','noun','분리 가능성 조항','A clause allowing invalid parts to be removed without voiding the rest.','The {severability} clause preserves the rest of the contract.','분리 가능성 조항이 계약의 나머지를 보존해요.','severability','B2','negotiation',2,'severability clause contract legal preserve'),
('w_negotiation_B2_28','performance bond','/pəˈfɔːməns bɒnd/','noun','이행 보증금','A guarantee that a party will fulfil its obligations.','The contractor posted a {performance bond}.','계약자가 이행 보증금을 예치했어요.','performance bond','B2','negotiation',2,'performance bond guarantee security contract'),
('w_negotiation_B2_29','good faith','/ɡʊd feɪθ/','noun','선의','Honest intention to deal fairly.','Both parties must act in {good faith}.','양 당사자는 선의로 행동해야 해요.','good faith','B2','negotiation',1,'good faith honesty trust cooperation fairness'),
('w_negotiation_B2_30','material breach','/məˈtɪəriəl briːtʃ/','noun','중대 위반','A serious failure to fulfil contractual obligations.','Late payment beyond 60 days is a {material breach}.','60일 초과 연체는 중대 위반이에요.','material breach','B2','negotiation',1,'material breach serious violation contract legal'),
('w_negotiation_B2_31','counterpart','/ˈkaʊntəpɑːt/','noun','거래 상대방','A person or thing with the same role on the other side.','Our legal team contacted their {counterpart}.','우리 법무팀이 상대방 법무팀에 연락했어요.','counterpart','B2','negotiation',2,'counterpart opposite side partner negotiation'),
('w_negotiation_B2_32','waiver','/ˈweɪvər/','noun','권리 포기','The act of voluntarily giving up a right.','Signing this form is a {waiver} of your claim.','이 양식에 서명하면 청구권을 포기하는 거예요.','waiver','B2','negotiation',1,'waiver relinquish right legal form signature'),
('w_negotiation_B2_33','retention','/rɪˈtenʃən/','noun','유보금, 보류','A sum withheld until work is satisfactorily completed.','A 10% {retention} is held until project handover.','프로젝트 인계까지 10% 유보금이 보류돼요.','retention','B2','negotiation',2,'retention holdback payment completion handover'),
('w_negotiation_B2_34','price cap','/praɪs kæp/','noun','가격 상한','A maximum price set by agreement or regulation.','The contract includes a {price cap} clause.','계약서에 가격 상한 조항이 포함돼 있어요.','price cap','B2','negotiation',2,'price cap maximum ceiling limit contract'),
('w_negotiation_B2_35','liquidated damages','/ˈlɪkwɪdeɪtɪd ˈdæmɪdʒɪz/','noun','손해배상 예정액','A pre-agreed sum payable if a party breaches a contract.','The contract specifies {liquidated damages} of 1% per day.','계약서에 하루 1%의 손해배상 예정액이 명시돼 있어요.','liquidated damages','B2','negotiation',1,'liquidated damages penalty contract legal fine');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C1_01','fiduciary','/fɪˈdjuːʃəri/','adjective','신탁의, 수탁자의','Relating to the trust placed in a person to manage assets.','The trustee owes {fiduciary} duties to beneficiaries.','수탁자는 수익자에게 신탁 의무를 집니다.','fiduciary','C1','negotiation',1,'fiduciary trust duty legal obligation finance'),
('w_negotiation_C1_02','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위변제','The substitution of one party for another in a legal claim.','After paying the claim, the insurer pursued {subrogation}.','청구를 지급한 후 보험사는 대위변제를 추구했어요.','subrogation','C1','negotiation',1,'subrogation insurance legal claim substitution'),
('w_negotiation_C1_03','indemnification','/ɪnˌdemnɪfɪˈkeɪʃən/','noun','손해 배상 계약','A contractual obligation to compensate another for losses.','The {indemnification} provision covers all legal costs.','손해 배상 조항은 모든 법적 비용을 포함해요.','indemnification','C1','negotiation',1,'indemnification legal contract protect compensation clause'),
('w_negotiation_C1_04','covenant','/ˈkʌvənənt/','noun','약정, 서약 조항','A formal agreement or promise, especially in a contract.','The non-compete {covenant} lasts for two years.','경쟁 금지 약정은 2년간 지속돼요.','covenant','C1','negotiation',1,'covenant promise agreement contract restriction'),
('w_negotiation_C1_05','lien','/liːn/','noun','유치권, 담보권','A right to keep possession of property until a debt is paid.','The bank holds a {lien} over the property.','은행이 그 부동산에 유치권을 보유하고 있어요.','lien','C1','negotiation',1,'lien property claim bank security debt'),
('w_negotiation_C1_06','injunction','/ɪnˈdʒʌŋkʃən/','noun','금지 명령','A court order requiring a party to do or stop something.','We sought an {injunction} to halt the project.','프로젝트를 중단시키기 위해 금지 명령을 구했어요.','injunction','C1','negotiation',1,'injunction court order legal halt stop'),
('w_negotiation_C1_07','breach','/briːtʃ/','noun','위반 (고급)','Failure to fulfil a contractual or legal obligation.','The supplier''s delay was a clear {breach} of contract.','공급업체의 지연은 명백한 계약 위반이었어요.','breach','C1','negotiation',1,'breach violation legal failure contract consequence'),
('w_negotiation_C1_08','remedy','/ˈremədi/','noun','구제책','A means of obtaining redress for a legal wrong.','Damages are the most common {remedy} for breach.','손해배상이 위반에 대한 가장 일반적인 구제책이에요.','remedy','C1','negotiation',1,'remedy solution legal redress compensation contract'),
('w_negotiation_C1_09','jurisdiction','/ˌdʒʊərɪsˈdɪkʃən/','noun','관할권 (고급)','The official power to make legal decisions for an area.','Disputes are subject to Singapore {jurisdiction}.','분쟁은 싱가포르 관할권에 따라요.','jurisdiction','C1','negotiation',1,'jurisdiction court legal authority territory law'),
('w_negotiation_C1_10','tortious','/ˈtɔːʃəs/','adjective','불법 행위의','Constituting a civil wrong giving rise to liability.','The company faced a {tortious} interference claim.','회사는 불법 행위 간섭 청구에 직면했어요.','tortious','C1','negotiation',1,'tort civil wrong liability legal claim'),
('w_negotiation_C1_11','privity','/ˈprɪvɪti/','noun','계약 당사자 관계','The direct legal relationship between contracting parties.','A third party has no rights due to lack of {privity}.','제3자는 계약 당사자 관계가 없어 권리가 없어요.','privity','C1','negotiation',1,'privity contract relationship parties direct'),
('w_negotiation_C1_12','estoppel','/ɪˈstɒpəl/','noun','금반언','A legal principle preventing a person from contradicting a previous statement.','The court applied {estoppel} to prevent the claim.','법원은 청구를 막기 위해 금반언을 적용했어요.','estoppel','C1','negotiation',1,'estoppel legal principle contradiction consistency court'),
('w_negotiation_C1_13','rescission','/rɪˈsɪʃən/','noun','계약 해제','The cancellation of a contract, restoring parties to original positions.','{Rescission} was granted due to misrepresentation.','허위 진술로 인해 계약 해제가 허용됐어요.','rescission','C1','negotiation',1,'rescission cancel contract restore original legal'),
('w_negotiation_C1_14','novation','/nəʊˈveɪʃən/','noun','계약 갱신, 채무 교체','The substitution of a new obligation for an old one.','{Novation} transferred all duties to the acquiring company.','계약 갱신으로 모든 의무가 인수 기업에 이전됐어요.','novation','C1','negotiation',1,'novation substitute new contract obligation transfer'),
('w_negotiation_C1_15','promissory','/ˈprɒmɪsəri/','adjective','약속의, 약속 어음의','Conveying or implying a promise.','A {promissory} note is evidence of a debt obligation.','약속 어음은 채무 의무의 증거예요.','promissory','C1','negotiation',1,'promissory note promise debt document finance'),
('w_negotiation_C1_16','executory','/ɪɡˈzekjʊtəri/','adjective','미이행의, 실행 중인','Not yet fully performed; remaining to be carried out.','Both parties still have {executory} obligations.','양 당사자에게 아직 미이행 의무가 있어요.','executory','C1','negotiation',1,'executory contract obligations pending performance'),
('w_negotiation_C1_17','liquidated','/ˈlɪkwɪdeɪtɪd/','adjective','확정된, 산정된','Settled or agreed upon in advance, as damages.','The parties agreed on {liquidated} damages of $500 per day.','당사자들은 하루 500달러의 확정 손해배상에 합의했어요.','liquidated','C1','negotiation',2,'liquidated damages fixed amount contract penalty'),
('w_negotiation_C1_18','specific performance','/spɪˈsɪfɪk pəˈfɔːməns/','noun','특정 이행','A court order requiring a party to perform contractual duties.','The buyer sought {specific performance} of the sale contract.','매수인은 매매 계약의 특정 이행을 구했어요.','specific performance','C1','negotiation',1,'specific performance court order fulfill obligation contract'),
('w_negotiation_C1_19','frustration','/frʌˈstreɪʃən/','noun','계약 이행 불능','The termination of a contract due to an unforeseen event.','{Frustration} of contract discharged both parties.','계약 이행 불능으로 양 당사자가 면제됐어요.','frustration','C1','negotiation',1,'frustration contract discharge impossible event legal'),
('w_negotiation_C1_20','implied term','/ɪmˈplaɪd tɜːm/','noun','묵시적 조항','A term not expressly stated but incorporated by law or custom.','An {implied term} of fitness for purpose applies.','목적 적합성의 묵시적 조항이 적용돼요.','implied term','C1','negotiation',2,'implied term contract unwritten law custom'),
('w_negotiation_C1_21','exculpatory clause','/ɪkˈskʌlpətəri klɔːz/','noun','면책 조항','A clause releasing a party from liability.','The {exculpatory clause} was deemed unenforceable.','면책 조항이 집행 불가능한 것으로 판단됐어요.','exculpatory clause','C1','negotiation',2,'exculpatory exemption liability clause contract'),
('w_negotiation_C1_22','assignment','/əˈsaɪnmənt/','noun','양도','Transfer of rights or obligations to a third party.','The contract prohibits {assignment} without consent.','계약은 동의 없는 양도를 금지해요.','assignment','C1','negotiation',1,'assignment transfer rights contract third party'),
('w_negotiation_C1_23','acceleration clause','/əkˌseləˈreɪʃən klɔːz/','noun','기한 이익 상실 조항','A clause making an entire debt payable immediately if a condition is breached.','Default triggers the {acceleration clause}.','채무불이행은 기한 이익 상실 조항을 발동시켜요.','acceleration clause','C1','negotiation',2,'acceleration clause immediate payment default contract'),
('w_negotiation_C1_24','indemnity cap','/ɪnˈdemnɪti kæp/','noun','배상 한도액','The maximum amount payable under an indemnity.','The {indemnity cap} is set at the contract value.','배상 한도액은 계약 금액으로 설정돼요.','indemnity cap','C1','negotiation',2,'indemnity cap maximum liability limit contract'),
('w_negotiation_C1_25','consequential loss','/kənˌsekwənʃəl lɒs/','noun','간접 손해','Loss that is a secondary result of a breach.','The contract excludes liability for {consequential loss}.','계약은 간접 손해에 대한 책임을 배제해요.','consequential loss','C1','negotiation',2,'consequential indirect loss contract exclusion legal'),
('w_negotiation_C1_26','set-off','/set ɒf/','noun','상계','The right to offset a debt against a counterclaim.','The client exercised its right of {set-off}.','의뢰인이 상계권을 행사했어요.','set-off','C1','negotiation',2,'set off offset debt counterclaim legal finance'),
('w_negotiation_C1_27','retention of title','/rɪˈtenʃən əv ˈtaɪtəl/','noun','소유권 유보','A clause keeping ownership with the seller until payment.','The {retention of title} clause protects the supplier.','소유권 유보 조항이 공급업체를 보호해요.','retention of title','C1','negotiation',1,'retention title ownership unpaid goods clause'),
('w_negotiation_C1_28','entire agreement clause','/ɪnˈtaɪər əˈɡriːmənt klɔːz/','noun','전체 합의 조항','A clause stating the contract is the complete agreement.','The {entire agreement clause} supersedes prior discussions.','전체 합의 조항이 이전 논의를 대체해요.','entire agreement clause','C1','negotiation',2,'entire agreement clause merger integration contract'),
('w_negotiation_C1_29','non-compete','/nɒn kəmˈpiːt/','adjective','경쟁 금지의','Restricting a party from engaging in competing activities.','The {non-compete} clause runs for 18 months post-contract.','경쟁 금지 조항은 계약 후 18개월간 적용돼요.','non-compete','C1','negotiation',1,'non-compete restriction competition clause contract'),
('w_negotiation_C1_30','step-in rights','/step ɪn raɪts/','noun','직접 이행권','The right to take over a contract from a defaulting party.','The lender exercised its {step-in rights}.','대출자가 직접 이행권을 행사했어요.','step-in rights','C1','negotiation',2,'step-in intervention take over default contractor'),
('w_negotiation_C1_31','conditions precedent','/kənˈdɪʃənz ˈpresɪdənt/','noun','선행 조건','Conditions that must be satisfied before a contract takes effect.','All {conditions precedent} must be met by closing.','모든 선행 조건은 클로징 전에 충족돼야 해요.','conditions precedent','C1','negotiation',1,'conditions precedent closing requirements contract effective'),
('w_negotiation_C1_32','variation order','/ˌveəriˈeɪʃən ˈɔːdər/','noun','변경 명령서','A formal instruction to alter the scope of work.','Each {variation order} must be approved in writing.','각 변경 명령서는 서면으로 승인돼야 해요.','variation order','C1','negotiation',2,'variation order change scope work construction'),
('w_negotiation_C1_33','contra proferentem','/ˌkɒntrə prəˈferəntem/','noun','불명확 조항의 제안자 불리 해석','The rule that ambiguous terms are read against the drafter.','The court applied {contra proferentem} to the clause.','법원은 해당 조항에 제안자 불리 원칙을 적용했어요.','contra proferentem','C1','negotiation',2,'ambiguous clause interpretation drafter legal principle'),
('w_negotiation_C1_34','force majeure clause','/ˌfɔːs mæˈʒɜːr klɔːz/','noun','불가항력 조항','A contract provision excusing non-performance due to extraordinary events.','The {force majeure clause} was invoked during the supply crisis.','공급 위기 동안 불가항력 조항이 발동됐어요.','force majeure clause','C1','negotiation',1,'force majeure clause contract disaster extraordinary event'),
('w_negotiation_C1_35','duty of care','/ˈdjuːti əv keər/','noun','주의 의무','A legal obligation to avoid acts likely to cause harm.','The advisor breached her {duty of care} to the client.','어드바이저가 의뢰인에 대한 주의 의무를 위반했어요.','duty of care','C1','negotiation',1,'duty of care negligence obligation standard professional');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_negotiation_C2_01','estoppel','/ɪˈstɒpəl/','noun','금반언의 원칙','A doctrine preventing a party from denying a previously asserted fact.','The court invoked {estoppel} to bar the defendant''s claim.','법원은 피고의 청구를 막기 위해 금반언을 발동했어요.','estoppel','C2','negotiation',1,'estoppel legal doctrine bar claim court principle'),
('w_negotiation_C2_02','novation','/nəʊˈveɪʃən/','noun','채무 인수, 계약 갱신','The act of replacing an old obligation with a new one, discharging the original party.','Through {novation}, the assignee assumed all liabilities.','계약 갱신을 통해 양수인이 모든 부채를 인수했어요.','novation','C2','negotiation',1,'novation contract replace obligation discharge legal'),
('w_negotiation_C2_03','rescission','/rɪˈsɪʃən/','noun','계약 취소','The cancellation of a contract and restoration of parties to their original state.','Fraudulent misrepresentation led to {rescission} of the agreement.','사기적 허위 진술이 계약 취소로 이어졌어요.','rescission','C2','negotiation',1,'rescission cancel contract restore legal fraud'),
('w_negotiation_C2_04','quantum meruit','/ˌkwɒntəm ˈmɛruːɪt/','noun','정당한 보수 청구권','A claim for reasonable payment for services rendered where no price was fixed.','The contractor claimed {quantum meruit} for completed work.','계약자가 완료된 작업에 대해 정당한 보수를 청구했어요.','quantum meruit','C2','negotiation',1,'quantum meruit payment services reasonable legal claim'),
('w_negotiation_C2_05','tortious','/ˈtɔːʃəs/','adjective','불법 행위를 구성하는','Of the nature of a tort; giving rise to civil liability.','The conduct was deemed {tortious} interference with business.','그 행위는 영업에 대한 불법 행위 간섭으로 판단됐어요.','tortious','C2','negotiation',1,'tortious tort civil wrong liability interference business'),
('w_negotiation_C2_06','mens rea','/menz ˈriːə/','noun','범의 (형사 책임의 주관적 요소)','The mental element of criminal intent required to convict.','Prosecutors must prove {mens rea} beyond reasonable doubt.','검사는 합리적 의심 없이 범의를 입증해야 해요.','mens rea','C2','negotiation',1,'mens rea criminal intent mental element law prosecution'),
('w_negotiation_C2_07','actus reus','/ˌæktəs ˈriːəs/','noun','범죄 행위 (형사 책임의 객관적 요소)','The physical act forming the objective element of a crime.','The {actus reus} of theft was confirmed by CCTV.','절도의 범죄 행위는 CCTV로 확인됐어요.','actus reus','C2','negotiation',1,'actus reus physical act crime element evidence'),
('w_negotiation_C2_08','promissory estoppel','/ˈprɒmɪsəri ɪˈstɒpəl/','noun','약속적 금반언','A doctrine preventing a party from going back on a clear promise relied upon.','The court applied {promissory estoppel} to enforce the promise.','법원은 약속을 집행하기 위해 약속적 금반언을 적용했어요.','promissory estoppel','C2','negotiation',1,'promissory estoppel promise enforce reliance legal doctrine'),
('w_negotiation_C2_09','executory contract','/ɪɡˈzekjʊtəri ˈkɒntrækt/','noun','미이행 계약','A contract where obligations on both sides are yet to be performed.','The acquisition included several {executory contracts}.','인수에는 여러 미이행 계약이 포함됐어요.','executory contract','C2','negotiation',1,'executory contract unperformed obligations pending legal'),
('w_negotiation_C2_10','liquidated damages','/ˈlɪkwɪdeɪtɪd ˈdæmɪdʒɪz/','noun','약정 손해배상액','A pre-agreed sum specified in a contract as compensation for breach.','The {liquidated damages} clause set $1,000 per day of delay.','약정 손해배상액 조항은 지연 하루당 1,000달러로 설정됐어요.','liquidated damages','C2','negotiation',1,'liquidated damages penalty breach contract pre-agreed fine'),
('w_negotiation_C2_11','unjust enrichment','/ʌnˈdʒʌst ɪnˈrɪtʃmənt/','noun','부당 이득','The unfair benefit received at another party''s expense.','The claim was based on {unjust enrichment} principles.','청구는 부당 이득 원칙에 근거했어요.','unjust enrichment','C2','negotiation',1,'unjust enrichment unfair benefit legal restitution claim'),
('w_negotiation_C2_12','restitution','/ˌrestɪˈtjuːʃən/','noun','원상 회복, 반환','Restoration of something lost or payment for damage caused.','The court ordered full {restitution} of amounts paid.','법원은 지불된 금액의 전액 반환을 명령했어요.','restitution','C2','negotiation',1,'restitution restore return payment legal remedy'),
('w_negotiation_C2_13','nemo dat','/ˌniːməʊ ˈdæt/','noun','권리 이전 불가 원칙','The principle that one cannot transfer greater rights than one possesses.','The {nemo dat} rule voided the buyer''s claim to title.','권리 이전 불가 원칙이 매수인의 소유권 청구를 무효로 했어요.','nemo dat','C2','negotiation',1,'nemo dat title transfer legal principle ownership'),
('w_negotiation_C2_14','contra proferentem','/ˌkɒntrə prəˈferəntem/','noun','작성자 불이익 해석 원칙','The rule that ambiguous contractual terms are construed against the drafter.','The judge applied {contra proferentem} to limit liability.','판사는 책임을 제한하기 위해 작성자 불이익 원칙을 적용했어요.','contra proferentem','C2','negotiation',1,'contra proferentem ambiguous clause drafter legal interpret'),
('w_negotiation_C2_15','frustration of purpose','/frʌˈstreɪʃən əv ˈpɜːpəs/','noun','목적 이행 불능','Termination of a contract when an unforeseen event defeats its main purpose.','The pandemic triggered {frustration of purpose} claims.','팬데믹이 목적 이행 불능 청구를 촉발했어요.','frustration of purpose','C2','negotiation',1,'frustration purpose contract discharge unforeseen event'),
('w_negotiation_C2_16','in pari delicto','/ɪn ˌpærɪ dɪˈlɪktəʊ/','noun','동등 과실의 원칙','A doctrine denying relief when both parties are equally at fault.','The court dismissed the claim under {in pari delicto}.','법원은 동등 과실 원칙에 따라 청구를 기각했어요.','in pari delicto','C2','negotiation',2,'equal fault doctrine legal dismiss claim court'),
('w_negotiation_C2_17','clean hands doctrine','/kliːn hændz ˈdɒktrɪn/','noun','형평법상 청결 원칙','A principle that a party seeking equitable relief must not itself be at fault.','The defendant raised the {clean hands doctrine} as a defence.','피고가 형평법상 청결 원칙을 방어로 제기했어요.','clean hands doctrine','C2','negotiation',2,'clean hands equity fairness legal doctrine defence'),
('w_negotiation_C2_18','mutuality of obligation','/mjuːˈtʃuːəlɪti əv ˌɒblɪˈɡeɪʃən/','noun','쌍방 의무','The requirement that both parties must be bound for a contract to be valid.','Lack of {mutuality of obligation} made the contract voidable.','쌍방 의무가 없어 계약이 취소 가능하게 됐어요.','mutuality of obligation','C2','negotiation',2,'mutuality obligation contract valid both parties bound'),
('w_negotiation_C2_19','champerty','/ˈtʃæmpəti/','noun','소송 지원 및 이익 분배 계약','An arrangement where a third party funds litigation in exchange for a share of proceeds.','The funding arrangement was challenged as {champerty}.','자금 조달 약정이 소송 지원 계약으로 이의 제기됐어요.','champerty','C2','negotiation',2,'champerty litigation funding third party legal share'),
('w_negotiation_C2_20','subrogation','/ˌsʌbrəˈɡeɪʃən/','noun','대위 청구권','A right allowing one party to substitute for another in a legal claim.','Insurers exercise {subrogation} rights after settling claims.','보험사는 청구를 해결한 후 대위 청구권을 행사해요.','subrogation','C2','negotiation',1,'subrogation insurance legal right substitute claim'),
('w_negotiation_C2_21','laches','/ˈlætʃɪz/','noun','권리 해태','An unreasonable delay in asserting a legal claim.','The claim was barred by {laches}.','청구가 권리 해태로 차단됐어요.','laches','C2','negotiation',1,'laches delay legal claim equity bar'),
('w_negotiation_C2_22','piercing the veil','/ˌpɪəsɪŋ ðə veɪl/','noun','법인격 부인','Treating a company and its shareholders as a single legal entity.','The court allowed {piercing the veil} to recover debts.','법원은 채무 회수를 위해 법인격 부인을 허용했어요.','piercing the veil','C2','negotiation',1,'piercing veil corporate liability shareholder legal'),
('w_negotiation_C2_23','nunc pro tunc','/nʌŋk prəʊ tʌŋk/','noun','소급 효력 명령','A court order that takes effect from an earlier date.','The judge issued a {nunc pro tunc} order to correct the record.','판사는 기록을 수정하기 위해 소급 효력 명령을 발부했어요.','nunc pro tunc','C2','negotiation',2,'nunc pro tunc retroactive court order date record'),
('w_negotiation_C2_24','ab initio','/æb ɪˈnɪtɪəʊ/','adverb','처음부터 (법적으로)','From the beginning; describing something void from the start.','The contract was void {ab initio} due to fraud.','사기로 인해 계약은 처음부터 무효였어요.','ab initio','C2','negotiation',1,'ab initio void beginning contract fraud legal'),
('w_negotiation_C2_25','economic duress','/ˌiːkəˈnɒmɪk djʊˈres/','noun','경제적 강박','Illegitimate economic pressure applied to force contract formation.','The claimant alleged {economic duress} during negotiations.','청구인은 협상 중 경제적 강박이 있었다고 주장했어요.','economic duress','C2','negotiation',1,'economic duress coercion contract voidable pressure legal'),
('w_negotiation_C2_26','affirmation','/ˌæfəˈmeɪʃən/','noun','계약 존속 선택','The act of electing to affirm a voidable contract rather than rescind it.','By continuing to perform, the buyer made an {affirmation}.','이행을 계속함으로써 매수인이 계약 존속을 선택했어요.','affirmation','C2','negotiation',2,'affirmation voidable contract choice ratify legal'),
('w_negotiation_C2_27','equitable estoppel','/ˌekwɪtəbəl ɪˈstɒpəl/','noun','형평법상 금반언','A doctrine in equity preventing a party from asserting rights inconsistent with a prior representation.','The court upheld {equitable estoppel} in favour of the tenant.','법원이 세입자에게 유리한 형평법상 금반언을 지지했어요.','equitable estoppel','C2','negotiation',1,'equitable estoppel equity representation reliance legal'),
('w_negotiation_C2_28','offer and acceptance','/ˈɒfər ənd əkˈseptəns/','noun','청약과 승낙','The two elements forming the basis of a binding contract.','Valid {offer and acceptance} occurred on the phone.','유효한 청약과 승낙이 전화로 이루어졌어요.','offer and acceptance','C2','negotiation',1,'offer acceptance contract formation legal elements'),
('w_negotiation_C2_29','rectification','/ˌrektɪfɪˈkeɪʃən/','noun','계약서 수정 (법원에 의한)','A court order correcting a written document to reflect the parties'' true intention.','The court granted {rectification} of the mistaken clause.','법원이 잘못된 조항의 수정을 허가했어요.','rectification','C2','negotiation',2,'rectification correct document intention court legal'),
('w_negotiation_C2_30','solus agreement','/ˈsəʊləs əˈɡriːmənt/','noun','독점 공급 계약','An agreement tying a party to a single supplier.','The {solus agreement} with the refinery was challenged.','정제소와의 독점 공급 계약이 이의 제기됐어요.','solus agreement','C2','negotiation',2,'solus exclusive supply tie-in agreement contract'),
('w_negotiation_C2_31','champerty and maintenance','/ˈtʃæmpəti ənd ˈmeɪntənəns/','noun','소송 지원 금지 원칙','The doctrines prohibiting improper third-party involvement in litigation.','The agreement was void for {champerty and maintenance}.','계약은 소송 지원 금지 원칙으로 무효였어요.','champerty and maintenance','C2','negotiation',2,'champerty maintenance litigation invalid public policy'),
('w_negotiation_C2_32','cy-pres','/siː ˈpreɪ/','noun','유사 목적 원칙','A doctrine applying funds to a purpose as close as possible to the original.','The court applied {cy-pres} to redirect the charitable funds.','법원은 자선 기금을 전용하기 위해 유사 목적 원칙을 적용했어요.','cy-pres','C2','negotiation',2,'cy-pres trust fund redirect charitable purpose legal'),
('w_negotiation_C2_33','non est factum','/nɒn est ˈfæktəm/','noun','서명 착오의 항변','A plea that a signed document was fundamentally different from what was intended.','The signatory pleaded {non est factum} to void the deed.','서명자는 증서를 무효화하기 위해 서명 착오를 주장했어요.','non est factum','C2','negotiation',2,'non est factum signed document fundamental mistake plea'),
('w_negotiation_C2_34','caveat emptor','/ˌkæviæt ˈemptɔːr/','noun','구매자 위험 부담 원칙','The principle that buyers must take care to inspect goods before purchase.','The sale was governed by {caveat emptor}.','매매는 구매자 위험 부담 원칙에 따라 이루어졌어요.','caveat emptor','C2','negotiation',1,'caveat emptor buyer beware inspection goods legal'),
('w_negotiation_C2_35','uberrimae fidei','/juːˌberɪmiː ˈfɪdɪˌaɪ/','noun','최고 선의의 원칙','The principle requiring utmost good faith, especially in insurance contracts.','Insurance contracts demand {uberrimae fidei} from both parties.','보험 계약은 양 당사자에게 최고 선의를 요구해요.','uberrimae fidei','C2','negotiation',1,'uberrimae fidei utmost good faith insurance contract legal');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A1_01','story','/ˈstɔːri/','noun','이야기','A description of events, real or imagined.','She told us a {story} before bed.','그녀는 자기 전에 우리에게 이야기를 해줬어요.','story','A1','humanities',1,'book open story reading'),
('w_humanities_A1_02','book','/bʊk/','noun','책','A written work published in printed or digital form.','I read a {book} every month.','저는 매달 책을 한 권 읽어요.','book','A1','humanities',1,'book shelf library read'),
('w_humanities_A1_03','read','/riːd/','verb','읽다','To look at and understand written words.','Do you like to {read} in the morning?','아침에 독서하는 걸 좋아하세요?','read','A1','humanities',1,'person reading book open'),
('w_humanities_A1_04','write','/raɪt/','verb','쓰다','To mark words or symbols on a surface.','She loves to {write} short stories.','그녀는 단편 소설 쓰는 것을 좋아해요.','write','A1','humanities',1,'pen paper writing notebook'),
('w_humanities_A1_05','poem','/ˈpoʊɪm/','noun','시','A piece of writing in verse, often with rhythm.','He read a beautiful {poem} at the ceremony.','그는 행사에서 아름다운 시를 낭독했어요.','poem','A1','humanities',2,'poetry book writing verse'),
('w_humanities_A1_06','song','/sɒŋ/','noun','노래','A short piece of music with words.','She wrote a {song} about her hometown.','그녀는 고향에 대한 노래를 썼어요.','song','A1','humanities',1,'music notes singing guitar'),
('w_humanities_A1_07','history','/ˈhɪstəri/','noun','역사','The study of past events.','We studied the {history} of ancient civilizations.','우리는 고대 문명의 역사를 공부했어요.','history','A1','humanities',1,'ancient history books archive'),
('w_humanities_A1_08','old','/oʊld/','adjective','오래된','Having existed or lived for a long time.','This is an {old} and famous novel.','이것은 오래되고 유명한 소설이에요.','old','A1','humanities',2,'old books vintage library'),
('w_humanities_A1_09','people','/ˈpiːpəl/','noun','사람들','Human beings in general.','{People} love stories that feel real.','사람들은 현실적으로 느껴지는 이야기를 좋아해요.','people','A1','humanities',1,'crowd people gathering social'),
('w_humanities_A1_10','word','/wɜːrd/','noun','단어','A single unit of language.','What does this {word} mean in English?','이 단어는 영어로 무슨 뜻이에요?','word','A1','humanities',1,'dictionary words letters text'),
('w_humanities_A1_11','name','/neɪm/','noun','이름','A word used to identify a person or thing.','What is the {name} of this poem?','이 시의 제목이 뭐예요?','name','A1','humanities',2,'name tag label identity'),
('w_humanities_A1_12','page','/peɪdʒ/','noun','페이지','One side of a sheet of paper in a book.','Open your book to {page} ten.','책의 10페이지를 펴세요.','page','A1','humanities',2,'book page open reading'),
('w_humanities_A1_13','picture','/ˈpɪktʃər/','noun','그림, 사진','A drawing, painting, or photograph.','There is a {picture} in every chapter.','모든 챕터에 그림이 있어요.','picture','A1','humanities',2,'illustration art painting book'),
('w_humanities_A1_14','letter','/ˈletər/','noun','편지; 글자','A written message sent to someone; a symbol in an alphabet.','She wrote a long {letter} to her friend.','그녀는 친구에게 긴 편지를 썼어요.','letter','A1','humanities',2,'letter envelope pen writing'),
('w_humanities_A1_15','learn','/lɜːrn/','verb','배우다','To gain knowledge or a skill through study or experience.','We {learn} new words by reading books.','우리는 독서를 통해 새 단어를 배워요.','learn','A1','humanities',1,'study learning book education'),
('w_humanities_A1_16','love','/lʌv/','noun','사랑; 좋아함','An intense feeling of affection; great enjoyment.','Her {love} for literature started early.','그녀의 문학에 대한 사랑은 일찍 시작됐어요.','love','A1','humanities',1,'heart love passion books'),
('w_humanities_A1_17','life','/laɪf/','noun','삶, 인생','The existence of a human being.','Good novels reflect real {life}.','좋은 소설은 현실의 삶을 반영해요.','life','A1','humanities',1,'life journey human nature'),
('w_humanities_A1_18','title','/ˈtaɪtəl/','noun','제목','The name of a book, film, or other work.','What is the {title} of your favorite book?','가장 좋아하는 책의 제목이 뭐예요?','title','A1','humanities',2,'book cover title label'),
('w_humanities_A1_19','question','/ˈkwɛstʃən/','noun','질문','A sentence asking for information.','The author raises an important {question}.','작가는 중요한 질문을 제기해요.','question','A1','humanities',2,'question mark thinking wonder'),
('w_humanities_A1_20','think','/θɪŋk/','verb','생각하다','To have thoughts or opinions about something.','What do you {think} about the ending?','결말에 대해 어떻게 생각하세요?','think','A1','humanities',1,'thinking reflection idea mind'),
('w_humanities_A1_21','true','/truː/','adjective','사실인, 진짜의','In accordance with fact or reality.','The story is based on {true} events.','그 이야기는 실제 사건을 바탕으로 해요.','true','A1','humanities',2,'truth reality fact document'),
('w_humanities_A1_22','beautiful','/ˈbjuːtɪfəl/','adjective','아름다운','Pleasing to the senses or mind.','She wrote a {beautiful} poem for the class.','그녀는 수업을 위해 아름다운 시를 썼어요.','beautiful','A1','humanities',3,'beauty art landscape poem'),
('w_humanities_A1_23','short','/ʃɔːrt/','adjective','짧은','Small in length or time.','I prefer {short} stories to long novels.','저는 긴 소설보다 단편을 더 좋아해요.','short','A1','humanities',2,'short story brief pages'),
('w_humanities_A1_24','language','/ˈlæŋɡwɪdʒ/','noun','언어','A system of communication used by a group.','English is a global {language}.','영어는 세계 언어예요.','language','A1','humanities',1,'language communication speech text'),
('w_humanities_A1_25','draw','/drɔː/','verb','그리다','To make a picture with a pencil or pen.','She likes to {draw} characters from her favorite stories.','그녀는 좋아하는 이야기의 등장인물을 그리는 걸 좋아해요.','draw','A1','humanities',3,'drawing art sketch pencil'),
('w_humanities_A1_26','end','/end/','noun','끝, 결말','The final part of something.','The {end} of the story surprised everyone.','이야기의 결말이 모두를 놀라게 했어요.','end','A1','humanities',2,'ending story conclusion book'),
('w_humanities_A1_27','start','/stɑːrt/','verb','시작하다','To begin something.','Where does the story {start}?','이야기가 어디서 시작되나요?','start','A1','humanities',2,'beginning start open book'),
('w_humanities_A1_28','tell','/tel/','verb','말하다, 이야기하다','To communicate facts or a story in spoken or written words.','Can you {tell} me about your favorite book?','좋아하는 책에 대해 이야기해 줄 수 있어요?','tell','A1','humanities',1,'talking storytelling sharing'),
('w_humanities_A1_29','mean','/miːn/','verb','의미하다','To intend to convey; to signify.','What does this phrase {mean}?','이 구절은 무슨 뜻이에요?','mean','A1','humanities',1,'meaning definition understanding'),
('w_humanities_A1_30','listen','/ˈlɪsən/','verb','듣다','To pay attention to sounds.','I love to {listen} to audiobooks.','저는 오디오북 듣는 걸 좋아해요.','listen','A1','humanities',2,'listening audio headphones book'),
('w_humanities_A1_31','enjoy','/ɪnˈdʒɔɪ/','verb','즐기다','To take pleasure in something.','I {enjoy} reading classic literature.','저는 고전 문학 읽는 걸 즐겨요.','enjoy','A1','humanities',1,'enjoying reading leisure books'),
('w_humanities_A1_32','world','/wɜːrld/','noun','세계, 세상','The earth and all its people; a realm of existence.','Great literature opens up the {world}.','훌륭한 문학은 세계를 열어줘요.','world','A1','humanities',1,'world globe earth explore'),
('w_humanities_A1_33','real','/riːl/','adjective','진짜의, 현실의','Actually existing; not imagined.','The characters feel very {real}.','등장인물들이 매우 현실적으로 느껴져요.','real','A1','humanities',2,'reality authentic genuine truth'),
('w_humanities_A1_34','class','/klɑːs/','noun','수업; 계층','A group lesson; also a social division.','We discussed the poem in {class}.','수업에서 그 시에 대해 토론했어요.','class','A1','humanities',2,'classroom learning education discussion'),
('w_humanities_A1_35','remember','/rɪˈmembər/','verb','기억하다','To have in mind or bring back to mind.','I always {remember} the first book I loved.','저는 처음 좋아했던 책을 항상 기억해요.','remember','A1','humanities',2,'memory remember nostalgia books');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_A2_01','author','/ˈɔːθər/','noun','작가','A person who writes books or articles.','My favorite {author} has written over twenty novels.','제가 가장 좋아하는 작가는 소설을 20편 넘게 썼어요.','author','A2','humanities',1,'writer author desk books'),
('w_humanities_A2_02','novel','/ˈnɒvəl/','noun','소설','A long fictional prose narrative.','I just finished reading a great {novel}.','방금 훌륭한 소설을 다 읽었어요.','novel','A2','humanities',1,'novel book fiction reading'),
('w_humanities_A2_03','character','/ˈkærɪktər/','noun','등장인물; 성격','A person in a story or play; a person''s nature.','The main {character} changes throughout the story.','주인공은 이야기 내내 변해가요.','character','A2','humanities',1,'character portrait story person'),
('w_humanities_A2_04','chapter','/ˈtʃæptər/','noun','챕터, 장','A main division of a book.','I read two {chapter}s before bed every night.','저는 매일 밤 자기 전에 챕터를 두 개 읽어요.','chapter','A2','humanities',2,'book chapter pages reading'),
('w_humanities_A2_05','culture','/ˈkʌltʃər/','noun','문화','The customs and values of a society.','Literature reflects the {culture} of its time.','문학은 시대의 문화를 반영해요.','culture','A2','humanities',1,'culture diversity society tradition'),
('w_humanities_A2_06','tradition','/trəˈdɪʃən/','noun','전통','A long-established custom passed down through generations.','Oral storytelling is an important {tradition}.','구전 이야기하기는 중요한 전통이에요.','tradition','A2','humanities',2,'tradition heritage culture folk'),
('w_humanities_A2_07','myth','/mɪθ/','noun','신화','A traditional story, especially one explaining a natural phenomenon.','The Greek {myth} of Icarus is still famous.','이카로스에 관한 그리스 신화는 아직도 유명해요.','myth','A2','humanities',2,'mythology ancient Greece story'),
('w_humanities_A2_08','legend','/ˈledʒənd/','noun','전설','A traditional story about a famous person or event.','King Arthur is a well-known English {legend}.','아서 왕은 유명한 영국 전설이에요.','legend','A2','humanities',2,'legend folklore hero ancient'),
('w_humanities_A2_09','hero','/ˈhɪərəʊ/','noun','영웅; 주인공','A person admired for courage; the main character.','Every great story has a {hero} who faces challenges.','모든 훌륭한 이야기에는 도전에 맞서는 영웅이 있어요.','hero','A2','humanities',1,'hero courage adventure story'),
('w_humanities_A2_10','describe','/dɪˈskraɪb/','verb','묘사하다','To give a detailed account of something.','The author uses vivid language to {describe} the setting.','작가는 생생한 언어로 배경을 묘사해요.','describe','A2','humanities',1,'description detail writing vivid'),
('w_humanities_A2_11','imagination','/ɪˌmædʒɪˈneɪʃən/','noun','상상력','The ability to form new ideas not present to the senses.','Reading develops your {imagination}.','독서는 상상력을 키워줘요.','imagination','A2','humanities',1,'imagination creativity dream art'),
('w_humanities_A2_12','poetry','/ˈpoʊɪtri/','noun','시(詩) 전반','Literary work in verse, expressing feelings and ideas.','She studied {poetry} at university.','그녀는 대학에서 시를 공부했어요.','poetry','A2','humanities',2,'poetry book verse literature'),
('w_humanities_A2_13','fiction','/ˈfɪkʃən/','noun','소설, 허구','Literature that describes imaginary events and people.','Science {fiction} often predicts the future.','공상과학 소설은 종종 미래를 예측해요.','fiction','A2','humanities',2,'fiction books library story'),
('w_humanities_A2_14','drama','/ˈdrɑːmə/','noun','희곡; 드라마','A play for theatre or TV; an exciting series of events.','Shakespeare''s {drama} is still performed worldwide.','셰익스피어의 희곡은 전 세계에서 아직도 공연돼요.','drama','A2','humanities',2,'theater drama stage performance'),
('w_humanities_A2_15','express','/ɪkˈspres/','verb','표현하다','To convey feelings or ideas through words or art.','Writers {express} their inner world through stories.','작가들은 이야기를 통해 내면 세계를 표현해요.','express','A2','humanities',1,'expression art writing feeling'),
('w_humanities_A2_16','meaning','/ˈmiːnɪŋ/','noun','의미','What is intended or expressed.','What is the deeper {meaning} of this poem?','이 시의 더 깊은 의미는 무엇인가요?','meaning','A2','humanities',1,'meaning depth significance text'),
('w_humanities_A2_17','publish','/ˈpʌblɪʃ/','verb','출판하다','To prepare and issue a book or article for public sale.','Her debut novel was {publish}ed last spring.','그녀의 데뷔 소설은 지난 봄에 출판됐어요.','publish','A2','humanities',2,'publishing book print release'),
('w_humanities_A2_18','audience','/ˈɔːdiəns/','noun','독자; 관객','The group of people who read or watch a work.','The author writes for a young adult {audience}.','작가는 청소년 독자를 위해 글을 써요.','audience','A2','humanities',2,'audience readers crowd people'),
('w_humanities_A2_19','setting','/ˈsetɪŋ/','noun','배경','The time and place in which a story is set.','The {setting} of the novel is 19th-century London.','소설의 배경은 19세기 런던이에요.','setting','A2','humanities',2,'setting landscape scene place'),
('w_humanities_A2_20','plot','/plɒt/','noun','줄거리','The sequence of events in a story.','The {plot} of the movie was very unexpected.','영화의 줄거리가 매우 예상 밖이었어요.','plot','A2','humanities',1,'plot story twist narrative'),
('w_humanities_A2_21','inspire','/ɪnˈspaɪər/','verb','영감을 주다','To stimulate creative feeling or thought.','Great literature can {inspire} people to change.','훌륭한 문학은 사람들이 변화하도록 영감을 줄 수 있어요.','inspire','A2','humanities',1,'inspiration creativity idea art'),
('w_humanities_A2_22','compare','/kəmˈpeər/','verb','비교하다','To note the similarities and differences between two things.','Let''s {compare} these two short stories.','이 두 단편 소설을 비교해 봐요.','compare','A2','humanities',2,'comparison contrast analysis side'),
('w_humanities_A2_23','message','/ˈmesɪdʒ/','noun','메시지, 주제','The central idea or lesson of a work.','What {message} is the author trying to send?','작가가 전달하려는 메시지는 무엇인가요?','message','A2','humanities',2,'message meaning theme writing'),
('w_humanities_A2_24','century','/ˈsentʃəri/','noun','세기, 100년','A period of one hundred years.','This novel was written in the 19th {century}.','이 소설은 19세기에 쓰였어요.','century','A2','humanities',2,'century history timeline era'),
('w_humanities_A2_25','popular','/ˈpɒpjʊlər/','adjective','인기 있는','Liked or admired by many people.','This novel is very {popular} among teenagers.','이 소설은 십대들 사이에서 매우 인기 있어요.','popular','A2','humanities',2,'popular bestseller book trend'),
('w_humanities_A2_26','original','/əˈrɪdʒɪnəl/','adjective','독창적인; 원본의','New and creative; the first version of something.','The {original} manuscript is kept in a museum.','원본 원고는 박물관에 보관돼 있어요.','original','A2','humanities',2,'original authentic first edition'),
('w_humanities_A2_27','translate','/trænsˈleɪt/','verb','번역하다','To convert text from one language to another.','This novel has been {translate}d into 30 languages.','이 소설은 30개 언어로 번역됐어요.','translate','A2','humanities',2,'translation language global book'),
('w_humanities_A2_28','scene','/siːn/','noun','장면','A part of a play or story depicting a single event.','My favorite {scene} is at the end of chapter three.','제가 가장 좋아하는 장면은 3장 끝 부분이에요.','scene','A2','humanities',2,'scene movie play moment'),
('w_humanities_A2_29','creative','/kriˈeɪtɪv/','adjective','창의적인','Having the ability to produce new and imaginative ideas.','Writing requires a very {creative} mind.','글쓰기는 매우 창의적인 사고를 필요로 해요.','creative','A2','humanities',1,'creative imagination art design'),
('w_humanities_A2_30','opinion','/əˈpɪnjən/','noun','의견','A personal view or judgement.','In your {opinion}, what is the best novel ever written?','당신 의견으로는 역대 최고의 소설이 무엇이에요?','opinion','A2','humanities',1,'opinion view perspective discuss'),
('w_humanities_A2_31','award','/əˈwɔːrd/','noun','상, 수상','A prize given for achievement.','The novel won a major literary {award}.','그 소설은 주요 문학상을 받았어요.','award','A2','humanities',2,'award prize trophy achievement'),
('w_humanities_A2_32','ancient','/ˈeɪnʃənt/','adjective','고대의','Belonging to the very distant past.','{Ancient} myths still influence modern storytelling.','고대 신화는 아직도 현대 이야기 방식에 영향을 미쳐요.','ancient','A2','humanities',2,'ancient history ruins civilization'),
('w_humanities_A2_33','folktale','/ˈfoʊkteɪl/','noun','민담, 민화','A story passed down through ordinary people.','Korean {folktale}s often teach moral lessons.','한국 민담은 종종 도덕적 교훈을 가르쳐요.','folktale','A2','humanities',2,'folktale tradition culture story'),
('w_humanities_A2_34','narrative','/ˈnærətɪv/','noun','서사, 이야기 방식','A spoken or written account of events.','The {narrative} switches between two characters.','서사는 두 인물 사이를 오가요.','narrative','A2','humanities',1,'narrative storytelling structure plot'),
('w_humanities_A2_35','genre','/ˈʒɑːnrə/','noun','장르','A category of artistic work defined by style or subject.','What is your favorite literary {genre}?','가장 좋아하는 문학 장르가 뭐예요?','genre','A2','humanities',1,'genre category books shelf');
INSERT INTO words (id, en, ipa, pos, ko, definition, example_en, example_ko, highlight, cefr, topic_id, priority, image_keyword) VALUES
('w_humanities_B1_01','metaphor','/ˈmetəfɔːr/','noun','은유','A figure of speech applying a word or phrase to something it does not literally denote.','The author uses a powerful {metaphor} to describe grief.','작가는 슬픔을 묘사하기 위해 강력한 은유를 사용해요.','metaphor','B1','humanities',1,'metaphor language poetry figure'),
('w_humanities_B1_02','theme','/θiːm/','noun','주제, 테마','The central subject or idea explored in a work.','The main {theme} of the novel is redemption.','소설의 주된 주제는 구원이에요.','theme','B1','humanities',1,'theme idea central message'),
('w_humanities_B1_03','symbolism','/ˈsɪmbəlɪzəm/','noun','상징주의; 상징성','The use of symbols to represent ideas or qualities.','The green light in Gatsby is famous for its {symbolism}.','개츠비의 초록불은 상징성으로 유명해요.','symbolism','B1','humanities',1,'symbol meaning literature art'),
('w_humanities_B1_04','analyze','/ˈænəlaɪz/','verb','분석하다','To examine in detail to understand or explain.','Students are asked to {analyze} the poem''s structure.','학생들은 시의 구조를 분석하도록 요청받아요.','analyze','B1','humanities',1,'analysis research study detail'),
('w_humanities_B1_05','interpret','/ɪnˈtɜːrprɪt/','verb','해석하다','To explain the meaning of something.','How do you {interpret} the final scene?','마지막 장면을 어떻게 해석하세요?','interpret','B1','humanities',1,'interpretation meaning analysis view'),
('w_humanities_B1_06','literary','/ˈlɪtərəri/','adjective','문학적인','Relating to the writing or study of literature.','She has a deep appreciation for {literary} fiction.','그녀는 문학 소설을 깊이 좋아해요.','literary','B1','humanities',1,'literary books writing academic'),
('w_humanities_B1_07','classic','/ˈklæsɪk/','adjective / noun','고전적인; 고전 작품','Of recognized and enduring quality; a great work of art.','Romeo and Juliet is a {classic} of English literature.','로미오와 줄리엣은 영문학의 고전이에요.','classic','B1','humanities',1,'classic literature timeless book'),
('w_humanities_B1_08','critique','/krɪˈtiːk/','noun','비평','A detailed analysis and assessment of a work.','He wrote a {critique} of the novel for the magazine.','그는 잡지에 소설 비평을 썼어요.','critique','B1','humanities',2,'critique review analysis writing'),
('w_humanities_B1_09','perspective','/pərˈspektɪv/','noun','관점','A particular way of viewing something.','Read the story from the narrator''s {perspective}.','화자의 관점에서 이야기를 읽어보세요.','perspective','B1','humanities',1,'perspective viewpoint angle idea'),
('w_humanities_B1_10','contrast','/ˈkɒntræst/','noun','대비, 대조','The state of being strikingly different from something else.','The author uses sharp {contrast} to highlight injustice.','작가는 불의를 강조하기 위해 날카로운 대비를 사용해요.','contrast','B1','humanities',2,'contrast comparison black white'),
('w_humanities_B1_11','structure','/ˈstrʌktʃər/','noun','구조','The arrangement of and relations between the parts of a text.','The {structure} of this poem is unusual.','이 시의 구조는 독특해요.','structure','B1','humanities',2,'structure architecture design order'),
('w_humanities_B1_12','conflict','/ˈkɒnflɪkt/','noun','갈등','A serious disagreement; the central struggle in a narrative.','The internal {conflict} of the protagonist drives the story.','주인공의 내적 갈등이 이야기를 이끌어요.','conflict','B1','humanities',1,'conflict tension struggle drama'),
('w_humanities_B1_13','narrator','/nəˈreɪtər/','noun','화자, 서술자','The person who tells a story.','The {narrator} is unreliable, which creates suspense.','화자가 신뢰할 수 없어서 긴장감이 생겨요.','narrator','B1','humanities',2,'narrator voice storytelling book'),
('w_humanities_B1_14','tone','/toʊn/','noun','어조, 분위기','The general attitude of a writer toward the subject.','The {tone} of the poem shifts from joy to sadness.','시의 어조가 기쁨에서 슬픔으로 바뀌어요.','tone','B1','humanities',2,'tone mood atmosphere writing'),
('w_humanities_B1_15','imagery','/ˈɪmɪdʒəri/','noun','심상, 이미지','Visually descriptive or figurative language.','Rich {imagery} makes the poem come alive.','풍부한 심상이 시를 생동감 있게 만들어요.','imagery','B1','humanities',2,'imagery visualization poetry vivid'),
('w_humanities_B1_16','influence','/ˈɪnflʊəns/','noun','영향','The power to affect others.','Hemingway had a great {influence} on modern prose.','헤밍웨이는 현대 산문에 큰 영향을 미쳤어요.','influence','B1','humanities',1,'influence impact effect inspiration'),
('w_humanities_B1_17','context','/ˈkɒntekst/','noun','맥락, 문맥','The circumstances in which something exists or occurs.','Understanding the historical {context} helps us read the text better.','역사적 맥락을 이해하면 텍스트를 더 잘 읽을 수 있어요.','context','B1','humanities',1,'context background history text'),
('w_humanities_B1_18','symbol','/ˈsɪmbəl/','noun','상징','A thing representing or standing for something else.','The dove is a {symbol} of peace in many cultures.','비둘기는 많은 문화에서 평화의 상징이에요.','symbol','B1','humanities',1,'symbol peace dove meaning'),
('w_humanities_B1_19','biography','/baɪˈɒɡrəfi/','noun','전기(傳記)','An account of a person''s life written by someone else.','I read a {biography} of Shakespeare last year.','작년에 셰익스피어 전기를 읽었어요.','biography','B1','humanities',2,'biography life story portrait'),
('w_humanities_B1_20','tradition','/trəˈdɪʃən/','noun','문학 전통','A long-established custom or practice passed across generations.','Greek tragedy is central to the Western literary {tradition}.','그리스 비극은 서양 문학 전통의 핵심이에요.','tradition','B1','humanities',2,'tradition heritage classic western'),
('w_humanities_B1_21','tragedy','/ˈtrædʒɪdi/','noun','비극','A serious play or event with an unhappy ending.','Hamlet is one of Shakespeare''s greatest {tragedy} plays.','햄릿은 셰익스피어의 가장 위대한 비극 중 하나예요.','tragedy','B1','humanities',2,'tragedy drama sad ending stage'),
('w_humanities_B1_22','comedy','/ˈkɒmɪdi/','noun','희극','A play or story intended to be funny with a happy ending.','A Midsummer Night''s Dream is a celebrated {comedy}.','한여름 밤의 꿈은 유명한 희극이에요.','comedy','B1','humanities',3,'comedy humor play happy'),
('w_humanities_B1_23','verse','/vɜːrs/','noun','운문, 절','Writing arranged in lines with a rhythm; a stanza.','The poem is written in four-line {verse}s.','그 시는 4행 절로 쓰여 있어요.','verse','B1','humanities',2,'verse poetry rhyme stanza'),
('w_humanities_B1_24','prose','/proʊz/','noun','산문','Written or spoken language in its ordinary form.','The novel is written in beautiful, flowing {prose}.','소설은 아름답고 유려한 산문으로 쓰여 있어요.','prose','B1','humanities',2,'prose writing paragraphs style'),
('w_humanities_B1_25','reference','/ˈrefərəns/','noun','참조, 언급','A mention of or citation from another work.','The novel contains many {reference}s to Greek mythology.','소설에는 그리스 신화에 대한 언급이 많아요.','reference','B1','humanities',2,'reference citation source text'),
('w_humanities_B1_26','quotation','/kwoʊˈteɪʃən/','noun','인용문','A group of words repeated from a text.','She opened her essay with a {quotation} from Austen.','그녀는 오스틴의 인용문으로 에세이를 시작했어요.','quotation','B1','humanities',2,'quote citation text highlight'),
('w_humanities_B1_27','essay','/ˈeseɪ/','noun','에세이, 수필','A short piece of writing on a particular subject.','He wrote an {essay} comparing two famous novels.','그는 두 유명한 소설을 비교하는 에세이를 썼어요.','essay','B1','humanities',2,'essay writing analysis paper'),
('w_humanities_B1_28','respond','/rɪˈspɒnd/','verb','반응하다, 응하다','To say or write something in reply; to react.','How did readers {respond} to the new novel?','독자들은 새 소설에 어떻게 반응했나요?','respond','B1','humanities',2,'response reaction reader feedback'),
('w_humanities_B1_29','explore','/ɪkˈsplɔːr/','verb','탐구하다','To examine thoroughly; to investigate ideas.','The novel {explore}s themes of identity and belonging.','소설은 정체성과 귀속감의 주제를 탐구해요.','explore','B1','humanities',1,'explore discovery research idea'),
('w_humanities_B1_30','cultural','/ˈkʌltʃərəl/','adjective','문화적인','Relating to the culture of a society.','The novel has great {cultural} significance.','그 소설은 문화적으로 큰 의미를 지녀요.','cultural','B1','humanities',1,'cultural heritage society art'),
('w_humanities_B1_31','reveal','/rɪˈviːl/','verb','드러내다, 밝히다','To make known something previously hidden or unknown.','The final chapter {reveal}s the true identity of the killer.','마지막 챕터에서 살인자의 진짜 정체가 드러나요.','reveal','B1','humanities',2,'reveal surprise discovery truth'),
('w_humanities_B1_32','audience','/ˈɔːdiəns/','noun','독자, 청중','The intended readers or viewers of a work.','The book found a wide {audience} in Europe.','그 책은 유럽에서 넓은 독자층을 형성했어요.','audience','B1','humanities',2,'audience readers crowd reception'),
('w_humanities_B1_33','passage','/ˈpæsɪdʒ/','noun','구절, 단락','A short section taken from a longer text.','This {passage} from the novel is often quoted.','소설의 이 구절은 자주 인용돼요.','passage','B1','humanities',2,'passage text excerpt highlight'),
('w_humanities_B1_34','illustrate','/ˈɪləstreɪt/','verb','설명하다; 삽화를 넣다','To explain or make clear with examples or pictures.','The author uses anecdotes to {illustrate} the theme.','작가는 주제를 설명하기 위해 일화를 사용해요.','illustrate','B1','humanities',2,'illustration example visual explain'),
('w_humanities_B1_35','impact','/ˈɪmpækt/','noun','영향, 충격','A strong effect or impression.','This book had a huge {impact} on my life.','이 책은 제 삶에 큰 영향을 미쳤어요.','impact','B1','humanities',1,'impact effect change influence');
